import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ALLOWED_CUTS } from "../constants";
import { VisagismAnalysisResult } from "../types";

// In a real Next.js app, this would be server-side.
// For this SPA demo, we initialize it here.
const apiKey = process.env.API_KEY;

const ai = new GoogleGenAI({ apiKey: apiKey });

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    faceShape: {
      type: Type.STRING,
      description: "O formato do rosto identificado (ex: Oval, Quadrado, Redondo, etc).",
    },
    suggestedCuts: {
      type: Type.ARRAY,
      description: "Uma lista de 3 sugestões de cortes baseadas no formato do rosto.",
      items: {
        type: Type.OBJECT,
        properties: {
          name: {
            type: Type.STRING,
            description: `Nome do corte. DEVE ser exatamente um destes: ${ALLOWED_CUTS.join(", ")}`,
          },
          reason: {
            type: Type.STRING,
            description: "Justificativa curta (max 15 palavras) do porquê este corte combina com o rosto.",
          },
        },
        required: ["name", "reason"],
      },
    },
  },
  required: ["faceShape", "suggestedCuts"],
};

export const analyzeHairstyle = async (base64Image: string): Promise<VisagismAnalysisResult> => {
  if (!apiKey) {
    throw new Error("GEMINI_API_KEY não configurada. Verifique suas variáveis de ambiente.");
  }

  // Removing the data:image/jpeg;base64, prefix if present for the API call
  const base64Data = base64Image.split(',')[1] || base64Image;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg", // Assuming JPEG/PNG, the API is flexible with standard image types
              data: base64Data,
            },
          },
          {
            text: `
              Atue como um Visagista Profissional com anos de experiência.
              Analise a imagem fornecida, identifique o formato do rosto do cliente.
              Com base no formato, recomende as 3 melhores opções de corte de cabelo.

              IMPORTANTE:
              1. Você DEVE escolher os cortes ESTRITAMENTE desta lista: ${JSON.stringify(ALLOWED_CUTS)}. Não invente nomes.
              2. Forneça uma justificativa técnica mas simples para cada escolha.
              3. Responda APENAS com o JSON estruturado conforme o schema.
            `,
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        temperature: 0.4, // Lower temperature for more deterministic selection from the list
      },
    });

    const text = response.text;
    if (!text) throw new Error("Sem resposta da IA");

    return JSON.parse(text) as VisagismAnalysisResult;
  } catch (error) {
    console.error("Erro na análise de visagismo:", error);
    throw error;
  }
};

