export const generateHairstylePreview = async (base64Image: string, hairstyleName: string): Promise<string> => {
  if (!apiKey) {
    throw new Error("GEMINI_API_KEY não configurada.");
  }

  const base64Data = base64Image.split(',')[1] || base64Image;

  try {
    // Using gemini-2.5-flash-image for image editing/generation capabilities
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `Change the person's hairstyle to a ${hairstyleName}. 
