import React, { useState, useRef } from 'react';
import { Upload, Camera, CheckCircle2, AlertCircle, Loader2, Sparkles, User, RefreshCw, Eye, ImageIcon } from 'lucide-react';
import { analyzeHairstyle, generateHairstylePreview } from '../services/geminiService';
import { VisagismAnalysisResult } from '../types';

export const VisagismFeature: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<VisagismAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // State for image generation
  const [previewImages, setPreviewImages] = useState<Record<number, string>>({});
  const [loadingPreviews, setLoadingPreviews] = useState<Record<number, boolean>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      setError("A imagem deve ter no máximo 5MB.");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setImage(reader.result as string);
      setResult(null);
      setError(null);
      setPreviewImages({});
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!image) return;

    setLoading(true);
    setError(null);

    try {
      const analysis = await analyzeHairstyle(image);
      setResult(analysis);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Erro ao analisar a imagem. Verifique a API Key ou tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const handleGeneratePreview = async (index: number, cutName: string) => {
    if (!image) return;

    setLoadingPreviews(prev => ({ ...prev, [index]: true }));

    try {
      const generatedImage = await generateHairstylePreview(image, cutName);
      setPreviewImages(prev => ({ ...prev, [index]: generatedImage }));
    } catch (err) {
      console.error("Failed to generate preview", err);
      // Optional: Show a toast error here
    } finally {
      setLoadingPreviews(prev => ({ ...prev, [index]: false }));
    }
  };

  const handleReset = () => {
    setImage(null);
    setResult(null);
    setError(null);
    setPreviewImages({});
    setLoadingPreviews({});
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  return (
    <div id="visagismo" className="max-w-4xl mx-auto py-16 px-6">
      <div className="text-center mb-12">
        <h3 className="text-amber-500 font-bold uppercase tracking-wider text-sm mb-2">Feature Premium</h3>
        <h2 className="text-3xl md:text-4xl font-bold text-white mb-4">Visagismo com IA</h2>
        <p className="text-slate-400 max-w-2xl mx-auto">
          Envie uma selfie e nossa Inteligência Artificial analisará seu formato de rosto para recomendar os cortes que mais valorizam seus traços.
        </p>
      </div>

      {/* Upload Section */}
      {!result && (
        <div className="bg-slate-800/50 border border-slate-700 rounded-2xl p-8 backdrop-blur-sm">
          {!image ? (
            <div 
              className="border-2 border-dashed border-slate-600 rounded-xl p-12 text-center cursor-pointer hover:border-amber-500 hover:bg-slate-800 transition-all group"
              onClick={() => fileInputRef.current?.click()}
            >
              <div className="w-16 h-16 bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                <Camera className="w-8 h-8 text-slate-400 group-hover:text-amber-500" />
              </div>
              <h4 className="text-xl font-semibold text-white mb-2">Tire uma selfie ou envie uma foto</h4>
              <p className="text-slate-400 text-sm mb-6">Formatos: JPG, PNG (Max 5MB)</p>
              <button className="bg-slate-700 text-white px-6 py-2 rounded-full font-medium text-sm group-hover:bg-amber-600 transition-colors">
                Selecionar Arquivo
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                accept="image/*" 
                className="hidden" 
              />
            </div>
          ) : (
            <div className="flex flex-col items-center">
              <div className="relative w-64 h-64 mb-8 rounded-xl overflow-hidden border-4 border-slate-700 shadow-2xl">
                <img src={image} alt="Upload" className="w-full h-full object-cover" />
                <button 
                  onClick={handleReset}
                  className="absolute top-2 right-2 bg-black/60 text-white p-2 rounded-full hover:bg-red-500 transition-colors"
                >
                  <RefreshCw className="w-4 h-4" />
                </button>
              </div>

              {error && (
                <div className="bg-red-500/10 border border-red-500/50 text-red-200 px-4 py-3 rounded-lg flex items-center gap-2 mb-6 max-w-md w-full">
                  <AlertCircle className="w-5 h-5 flex-shrink-0" />
                  <p className="text-sm">{error}</p>
                </div>
              )}

              <button
                onClick={handleAnalyze}
                disabled={loading}
                className={`
                  w-full max-w-sm py-4 px-6 rounded-xl font-bold text-lg flex items-center justify-center gap-3 shadow-lg
                  ${loading 
                    ? 'bg-slate-700 text-slate-400 cursor-not-allowed' 
                    : 'bg-gradient-to-r from-amber-500 to-amber-600 text-slate-900 hover:scale-[1.02] hover:shadow-amber-500/25'
                  } transition-all
                `}
              >
                {loading ? (
                  <>
                    <Loader2 className="w-6 h-6 animate-spin" />
                    Analisando traços...
                  </>
                ) : (
                  <>
                    <Sparkles className="w-6 h-6" />
                    Analisar com Gemini
                  </>
                )}
              </button>
            </div>
          )}
        </div>
      )}

      {/* Results Section */}
      {result && (
        <div className="animate-fade-in">
          <div className="bg-slate-800 rounded-2xl p-8 border border-slate-700 mb-8 flex flex-col md:flex-row gap-8 items-center md:items-start">
            <div className="w-32 h-32 rounded-full border-4 border-amber-500 flex items-center justify-center bg-slate-900 flex-shrink-0 shadow-xl shadow-amber-900/20">
              <User className="w-16 h-16 text-amber-500" />
            </div>
            <div className="text-center md:text-left">
              <h3 className="text-slate-400 text-sm font-medium uppercase tracking-wide mb-1">Resultado da Análise</h3>
              <h2 className="text-3xl font-bold text-white mb-2">
                Seu rosto é <span className="text-amber-400">{result.faceShape}</span>
              </h2>
              <p className="text-slate-300 max-w-lg">
                Para este formato, selecionamos cortes que equilibram as proporções, 
                destacando seus melhores traços e suavizando ângulos.
              </p>
            </div>
            <div className="md:ml-auto">
               <button 
                onClick={handleReset} 
                className="text-sm text-slate-400 hover:text-white underline"
              >
                Nova análise
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {result.suggestedCuts.map((cut, index) => (
              <div 
                key={index} 
                className="bg-slate-800 border border-slate-700 rounded-xl overflow-hidden hover:border-amber-500/50 hover:bg-slate-800/80 transition-all group flex flex-col"
              >
                {/* Dynamic Content Area (Icon or Generated Image) */}
                <div className="relative w-full aspect-square bg-slate-900 flex items-center justify-center border-b border-slate-700/50">
                  {previewImages[index] ? (
                    <img 
                      src={previewImages[index]} 
                      alt={`Simulação ${cut.name}`} 
                      className="w-full h-full object-cover animate-fade-in"
                    />
                  ) : (
                    loadingPreviews[index] ? (
                       <div className="flex flex-col items-center gap-3 text-slate-400">
                         <Loader2 className="w-8 h-8 animate-spin text-amber-500" />
                         <span className="text-xs">Gerando imagem...</span>
                       </div>
                    ) : (
                      <div className="flex flex-col items-center gap-2">
                        <div className="w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center text-amber-500 mb-2">
                          <ScissorsIcon className="w-8 h-8" />
                        </div>
                        <p className="text-xs text-slate-500">Visualização pendente</p>
                      </div>
                    )
                  )}

                  {/* Overlay Button for Generation */}
                  {!previewImages[index] && !loadingPreviews[index] && (
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center backdrop-blur-sm">
                      <button 
                        onClick={() => handleGeneratePreview(index, cut.name)}
                        className="bg-white text-slate-900 px-4 py-2 rounded-full font-bold text-sm flex items-center gap-2 transform translate-y-2 group-hover:translate-y-0 transition-all"
                      >
                        <ImageIcon className="w-4 h-4" />
                        Visualizar no meu rosto
                      </button>
                    </div>
                  )}
                </div>

                <div className="p-6 flex flex-col flex-grow">
                  <h4 className="text-xl font-bold text-white mb-3">{cut.name}</h4>
                  <p className="text-slate-400 text-sm leading-relaxed mb-4 flex-grow">
                    {cut.reason}
                  </p>

                  <div className="pt-4 border-t border-slate-700/50 flex items-center justify-between mt-auto">
                    <span className="text-xs font-mono text-slate-500">Recomendação #{index + 1}</span>
                    <button className="text-amber-500 text-sm font-medium hover:underline">
                      Agendar este
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

