const apiKey = process.env.API_KEY;

const ai = new GoogleGenAI({ apiKey: apiKey });

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    faceShape: {
      type: Type.STRING,
      description: "O formato do rosto identificado (ex: Oval, Quadrado, Redondo, etc).",
    },
    suggestedCuts: {
      type: Type.ARRAY,
      description: "Uma lista de 6 a 12 sugestões de cortes baseadas no formato do rosto.",
      items: {
        type: Type.OBJECT,
