          reason: {
            type: Type.STRING,
            description: "Justificativa curta (max 15 palavras) do porquê este corte combina com o rosto.",
          },
        },
        required: ["name", "reason"],
      },
    },
  },
  required: ["faceShape", "suggestedCuts"],
};

export const analyzeHairstyle = async (base64Image: string): Promise<VisagismAnalysisResult> => {
  if (!apiKey) {
    throw new Error("GEMINI_API_KEY não configurada. Verifique suas variáveis de ambiente.");
  }

  // Removing the data:image/jpeg;base64, prefix if present for the API call
  const base64Data = base64Image.split(',')[1] || base64Image;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg", // Assuming JPEG/PNG, the API is flexible with standard image types
              data: base64Data,
            },
          },
          {
            text: `
              Atue como um Visagista Profissional com anos de experiência.
              Analise a imagem fornecida, identifique o formato do rosto do cliente.
              Com base no formato, recomende de 6 a 12 melhores opções de corte de cabelo que valorizem este rosto.

              IMPORTANTE:
              1. Você DEVE escolher os cortes ESTRITAMENTE desta lista: ${JSON.stringify(ALLOWED_CUTS)}. Não invente nomes.
              2. Busque variar as opções (curtos, médios, modernos, clássicos) dentro do que faz sentido para o rosto.
              3. Forneça uma justificativa técnica mas simples para cada escolha.
              4. Responda APENAS com o JSON estruturado conforme o schema.
            `,
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        temperature: 0.6, // Slightly higher temperature for better variety in a larger list
      },
    });

    const text = response.text;
    if (!text) throw new Error("Sem resposta da IA");

    return JSON.parse(text) as VisagismAnalysisResult;
  } catch (error) {
    console.error("Erro na análise de visagismo:", error);
    throw error;
  }
};

