import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ALLOWED_CUTS, ALLOWED_BEARDS, ALLOWED_EYEBROWS } from "../constants";
import { VisagismAnalysisResult, AnalysisCategory } from "../types";

// In a real Next.js app, this would be server-side.
// For this SPA demo, we initialize it here.
const apiKey = process.env.API_KEY;

const ai = new GoogleGenAI({ apiKey: apiKey });

const getAnalysisSchema = (allowedList: string[]): Schema => ({
  type: Type.OBJECT,
  properties: {
    faceShape: {
      type: Type.STRING,
      description: "O formato do rosto identificado (ex: Oval, Quadrado, Redondo, etc).",
    },
    suggestedCuts: {
      type: Type.ARRAY,
      description: "Uma lista de sugestões baseadas no formato do rosto.",
      items: {
        type: Type.OBJECT,
        properties: {
          name: {
            type: Type.STRING,
            description: `Nome do estilo. DEVE ser exatamente um destes: ${allowedList.join(", ")}`,
          },
          reason: {
            type: Type.STRING,
            description: "Justificativa curta (max 15 palavras) do porquê este estilo combina com o rosto.",
          },
        },
        required: ["name", "reason"],
      },
    },
  },
  required: ["faceShape", "suggestedCuts"],
});

export const analyzeHairstyle = async (
  base64Image: string, 
  stylePreference: string = "Todos",
  category: AnalysisCategory = 'hair'
): Promise<VisagismAnalysisResult> => {
  if (!apiKey) {
    throw new Error("GEMINI_API_KEY não configurada. Verifique suas variáveis de ambiente.");
  }

  // Removing the data:image/jpeg;base64, prefix if present for the API call
  const base64Data = base64Image.split(',')[1] || base64Image;

  let allowedList = ALLOWED_CUTS;
  let contextPrompt = "CORTES DE CABELO";

  if (category === 'beard') {
    allowedList = ALLOWED_BEARDS;
    contextPrompt = "ESTILOS DE BARBA E BIGODE (considere densidade e formato do queixo)";
  } else if (category === 'eyebrow') {
    allowedList = ALLOWED_EYEBROWS;
    contextPrompt = "DESIGN DE SOBRANCELHAS (considere o arco natural e expressão)";
  }

  const stylePrompt = stylePreference !== "Todos" && category === 'hair'
    ? `O cliente tem uma preferência explícita pelo estilo: "${stylePreference}". Dê prioridade total a estilos desta categoria.`
    : "Busque variar as opções para oferecer diversidade.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg", 
              data: base64Data,
            },
          },
          {
            text: `
              Atue como um Visagista Profissional com anos de experiência.
              Analise a imagem fornecida, identifique o formato do rosto do cliente.
              Com base no formato, recomende de 4 a 6 melhores opções de ${contextPrompt} que valorizem este rosto.

              IMPORTANTE:
              1. Você DEVE escolher os estilos ESTRITAMENTE desta lista: ${JSON.stringify(allowedList)}. Não invente nomes.
              2. ${stylePrompt}
              3. Forneça uma justificativa técnica mas simples para cada escolha.
              4. Responda APENAS com o JSON estruturado conforme o schema.
            `,
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: getAnalysisSchema(allowedList),
        temperature: 0.6, 
      },
    });

    const text = response.text;
    if (!text) throw new Error("Sem resposta da IA");

    return JSON.parse(text) as VisagismAnalysisResult;
  } catch (error) {
    console.error("Erro na análise de visagismo:", error);
    throw error;
  }
};

export const generateHairstylePreview = async (base64Image: string, styleName: string, category: AnalysisCategory = 'hair'): Promise<string> => {
  if (!apiKey) {
    throw new Error("GEMINI_API_KEY não configurada.");
  }

  const base64Data = base64Image.split(',')[1] || base64Image;

  let promptInstruction = "";
  if (category === 'hair') {
    promptInstruction = `Change the person's hairstyle to a ${styleName}.`;
  } else if (category === 'beard') {
    promptInstruction = `Change the person's beard/facial hair to a ${styleName}. Keep the hairstyle unchanged if possible.`;
  } else if (category === 'eyebrow') {
    promptInstruction = `Change the person's eyebrow shape to ${styleName}. Keep hairstyle and beard unchanged.`;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `${promptInstruction} 
                   Keep the original face features, skin tone, lighting, and background exactly as they are. 
                   Make it look photorealistic.`,
          },
        ],
      },
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          const base64EncodeString = part.inlineData.data;
          return `data:image/png;base64,${base64EncodeString}`;
        }
      }
    }

    throw new Error("Não foi possível gerar a imagem.");
  } catch (error) {
    console.error("Erro na geração de imagem:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Upload, Camera, CheckCircle2, AlertCircle, Loader2, Sparkles, User, RefreshCw, Eye, ImageIcon, Filter, Layers, Scissors, Smile } from 'lucide-react';
import { analyzeHairstyle, generateHairstylePreview } from '../services/geminiService';
import { VisagismAnalysisResult, AnalysisCategory } from '../types';
import { STYLE_PREFERENCES } from '../constants';

const LOADING_STEPS = [
  "Detectando geometria facial...",
  "Analisando proporções e simetria...",
  "Consultando base de visagismo...",
  "Selecionando melhores estilos para você..."
];

export const VisagismFeature: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [loadingStepIndex, setLoadingStepIndex] = useState(0);
  const [result, setResult] = useState<VisagismAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState<string>("Todos");
  const [category, setCategory] = useState<AnalysisCategory>('hair');

  // State for image generation
  const [previewImages, setPreviewImages] = useState<Record<number, string>>({});
  const [loadingPreviews, setLoadingPreviews] = useState<Record<number, boolean>>({});
  // State for Before/After toggle (true = show original, false = show generated)
  const [showOriginal, setShowOriginal] = useState<Record<number, boolean>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Effect to cycle loading messages
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (loading) {
      setLoadingStepIndex(0);
      interval = setInterval(() => {
        setLoadingStepIndex((prev) => (prev + 1) % LOADING_STEPS.length);
      }, 1500); // Change message every 1.5s
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      setError("A imagem deve ter no máximo 5MB.");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setImage(reader.result as string);
      setResult(null);
      setError(null);
      setPreviewImages({});
      setShowOriginal({});
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!image) return;

    setLoading(true);
    setError(null);

    try {
      const analysis = await analyzeHairstyle(image, selectedStyle, category);
      setResult(analysis);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Erro ao analisar a imagem. Verifique a API Key ou tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const handleGeneratePreview = async (index: number, cutName: string) => {
    if (!image) return;

    setLoadingPreviews(prev => ({ ...prev, [index]: true }));

    try {
      const generatedImage = await generateHairstylePreview(image, cutName, category);
      setPreviewImages(prev => ({ ...prev, [index]: generatedImage }));
      setShowOriginal(prev => ({ ...prev, [index]: false })); // Auto-switch to generated
    } catch (err) {
      console.error("Failed to generate preview", err);
      // Optional: Show a toast error here
    } finally {
      setLoadingPreviews(prev => ({ ...prev, [index]: false }));
    }
  };

  const toggleBeforeAfter = (index: number) => {
    setShowOriginal(prev => ({ ...prev, [index]: !prev[index] }));
  };

  const handleReset = () => {
    setImage(null);
    setResult(null);
    setError(null);
    setPreviewImages({});
    setLoadingPreviews({});
    setShowOriginal({});
    setSelectedStyle("Todos");
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  const handleCategoryChange = (newCat: AnalysisCategory) => {
    setCategory(newCat);
    // If we have an image but already have results for another category, we might want to reset results
    if (result) {
      setResult(null);
      setPreviewImages({});
      setShowOriginal({});
    }
  };

  return (
    <div id="visagismo" className="max-w-4xl mx-auto py-16 px-6">
      <div className="text-center mb-12">
        <h3 className="text-amber-500 font-bold uppercase tracking-wider text-sm mb-2">Feature Premium</h3>
        <h2 className="text-3xl md:text-4xl font-bold text-white mb-4">Visagismo com IA</h2>
        <p className="text-slate-400 max-w-2xl mx-auto">
          Envie uma selfie e nossa Inteligência Artificial analisará seu formato de rosto para recomendar os cortes que mais valorizam seus traços.
        </p>
      </div>

      {/* Category Tabs */}
      <div className="flex justify-center mb-8 gap-2">
        <button
          onClick={() => handleCategoryChange('hair')}
          className={`flex items-center gap-2 px-6 py-3 rounded-full font-bold transition-all ${category === 'hair' ? 'bg-amber-500 text-slate-900 shadow-lg shadow-amber-500/20' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
        >
          <Scissors className="w-5 h-5" /> Cabelo
        </button>
        <button
          onClick={() => handleCategoryChange('beard')}
          className={`flex items-center gap-2 px-6 py-3 rounded-full font-bold transition-all ${category === 'beard' ? 'bg-amber-500 text-slate-900 shadow-lg shadow-amber-500/20' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
        >
          <Smile className="w-5 h-5" /> Barba
        </button>
        <button
          onClick={() => handleCategoryChange('eyebrow')}
          className={`flex items-center gap-2 px-6 py-3 rounded-full font-bold transition-all ${category === 'eyebrow' ? 'bg-amber-500 text-slate-900 shadow-lg shadow-amber-500/20' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
        >
          <Eye className="w-5 h-5" /> Sobrancelha
        </button>
      </div>

      {/* Upload Section */}
      {!result && (
        <div className="bg-slate-800/50 border border-slate-700 rounded-2xl p-8 backdrop-blur-sm">
          {!image ? (
            <div 
              className="border-2 border-dashed border-slate-600 rounded-xl p-12 text-center cursor-pointer hover:border-amber-500 hover:bg-slate-800 transition-all group"
              onClick={() => fileInputRef.current?.click()}
            >
              <div className="w-16 h-16 bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                <Camera className="w-8 h-8 text-slate-400 group-hover:text-amber-500" />
              </div>
              <h4 className="text-xl font-semibold text-white mb-2">Tire uma selfie ou envie uma foto</h4>
              <p className="text-slate-400 text-sm mb-6">Formatos: JPG, PNG (Max 5MB)</p>
              <button className="bg-slate-700 text-white px-6 py-2 rounded-full font-medium text-sm group-hover:bg-amber-600 transition-colors">
                Selecionar Arquivo
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                accept="image/*" 
                className="hidden" 
              />
            </div>
          ) : (
            <div className="flex flex-col items-center">
              <div className="relative w-64 h-64 mb-6 rounded-xl overflow-hidden border-4 border-slate-700 shadow-2xl">
                <img src={image} alt="Upload" className="w-full h-full object-cover" />
                <button 
                  onClick={handleReset}
                  className="absolute top-2 right-2 bg-black/60 text-white p-2 rounded-full hover:bg-red-500 transition-colors"
                >
                  <RefreshCw className="w-4 h-4" />
                </button>
              </div>

              {/* Style Preference Filter (Only show for Hair) */}
              {category === 'hair' && (
                <div className="w-full max-w-xl mb-8">
                   <div className="flex items-center gap-2 mb-3 justify-center text-slate-300">
                      <Filter className="w-4 h-4 text-amber-500" />
                      <span className="text-sm font-medium">Filtrar estilo preferido (Opcional)</span>
                   </div>
                   <div className="flex flex-wrap justify-center gap-2">
                      {STYLE_PREFERENCES.map((style) => (
                        <button
                          key={style}
                          onClick={() => setSelectedStyle(style)}
                          className={`
                            px-4 py-2 rounded-full text-xs font-medium transition-all
                            ${selectedStyle === style 
                              ? 'bg-amber-500 text-slate-900 shadow-lg shadow-amber-500/20 scale-105' 
                              : 'bg-slate-700 text-slate-300 hover:bg-slate-600 hover:text-white'
                            }
                          `}
                        >
                          {style}
                        </button>
                      ))}
                   </div>
                </div>
              )}

              {error && (
                <div className="bg-red-500/10 border border-red-500/50 text-red-200 px-4 py-3 rounded-lg flex items-center gap-2 mb-6 max-w-md w-full">
                  <AlertCircle className="w-5 h-5 flex-shrink-0" />
                  <p className="text-sm">{error}</p>
                </div>
              )}

              <button
                onClick={handleAnalyze}
                disabled={loading}
                className={`
                  w-full max-w-sm py-4 px-6 rounded-xl font-bold text-lg flex items-center justify-center gap-3 shadow-lg
                  ${loading 
                    ? 'bg-slate-700 text-slate-400 cursor-not-allowed' 
                    : 'bg-gradient-to-r from-amber-500 to-amber-600 text-slate-900 hover:scale-[1.02] hover:shadow-amber-500/25'
                  } transition-all
                `}
              >
                {loading ? (
                  <div className="flex flex-col items-center">
                    <div className="flex items-center gap-2 mb-1">
                      <Loader2 className="w-6 h-6 animate-spin" />
                      <span>Processando...</span>
                    </div>
                    <span className="text-xs font-normal text-slate-300 animate-pulse">
                      {LOADING_STEPS[loadingStepIndex]}
                    </span>
                  </div>
                ) : (
                  <>
                    <Sparkles className="w-6 h-6" />
                    Analisar {category === 'hair' ? 'Cabelo' : category === 'beard' ? 'Barba' : 'Sobrancelhas'}
                  </>
                )}
              </button>
            </div>
          )}
        </div>
      )}

      {/* Results Section */}
      {result && (
        <div className="animate-fade-in">
          <div className="bg-slate-800 rounded-2xl p-8 border border-slate-700 mb-8 flex flex-col md:flex-row gap-8 items-center md:items-start">
            <div className="w-32 h-32 rounded-full border-4 border-amber-500 flex items-center justify-center bg-slate-900 flex-shrink-0 shadow-xl shadow-amber-900/20">
              <User className="w-16 h-16 text-amber-500" />
            </div>
            <div className="text-center md:text-left">
              <h3 className="text-slate-400 text-sm font-medium uppercase tracking-wide mb-1">Resultado da Análise ({category === 'hair' ? 'Cabelo' : category === 'beard' ? 'Barba' : 'Sobrancelha'})</h3>
              <h2 className="text-3xl font-bold text-white mb-2">
                Seu rosto é <span className="text-amber-400">{result.faceShape}</span>
              </h2>
              <div className="flex flex-col gap-2">
                 <p className="text-slate-300 max-w-lg">
                  Para este formato, selecionamos estilos que equilibram as proporções, 
                  destacando seus melhores traços e suavizando ângulos.
                </p>
                {category === 'hair' && selectedStyle !== "Todos" && (
                  <p className="text-amber-500/80 text-sm italic">
                    *Focando no estilo: {selectedStyle}
                  </p>
                )}
              </div>
            </div>
            <div className="md:ml-auto">
               <button 
                onClick={handleReset} 
                className="text-sm text-slate-400 hover:text-white underline"
              >
                Nova análise
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {result.suggestedCuts.map((cut, index) => {
              // Determine what to show: Original Image OR Generated Image OR Placeholder Icon
              const hasGenerated = !!previewImages[index];
              const isShowOriginal = showOriginal[index];
              const displayImage = (hasGenerated && !isShowOriginal) ? previewImages[index] : image!;

              return (
              <div 
                key={index} 
                className="bg-slate-800 border border-slate-700 rounded-xl overflow-hidden hover:border-amber-500/50 hover:bg-slate-800/80 transition-all group flex flex-col"
              >
                {/* Dynamic Content Area */}
                <div className="relative w-full aspect-square bg-slate-900 flex items-center justify-center border-b border-slate-700/50 overflow-hidden">

                  {loadingPreviews[index] ? (
                     <div className="flex flex-col items-center gap-3 text-slate-400">
                       <Loader2 className="w-8 h-8 animate-spin text-amber-500" />
                       <span className="text-xs">Gerando imagem...</span>
                     </div>
                  ) : hasGenerated || isShowOriginal ? (
                     <>
                        <img 
                          src={displayImage} 
                          alt={`Visualização ${cut.name}`} 
                          className="w-full h-full object-cover animate-fade-in transition-transform duration-500"
                        />
                        {/* Before/After Toggle Badge */}
                        <div className="absolute top-2 left-2">
                           <span className={`text-[10px] font-bold px-2 py-1 rounded-full ${isShowOriginal ? 'bg-slate-900/80 text-white border border-slate-600' : 'bg-amber-500 text-slate-900 shadow-lg'}`}>
                              {isShowOriginal ? 'ORIGINAL' : 'SIMULAÇÃO'}
                           </span>
                        </div>
                     </>
                  ) : (
                    <div className="flex flex-col items-center gap-2">
                      <div className="w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center text-amber-500 mb-2">
                        {category === 'hair' && <ScissorsIcon className="w-8 h-8" />}
                        {category === 'beard' && <Smile className="w-8 h-8" />}
                        {category === 'eyebrow' && <Eye className="w-8 h-8" />}
                      </div>
                      <p className="text-xs text-slate-500">Visualização pendente</p>
                    </div>
                  )}

                  {/* Action Buttons Overlay */}
                  {!loadingPreviews[index] && (
                    <div className={`absolute bottom-0 w-full p-4 flex justify-center gap-2 ${hasGenerated ? 'bg-gradient-to-t from-black/80 to-transparent' : 'bg-black/40 opacity-0 group-hover:opacity-100 backdrop-blur-sm'} transition-all`}>

                      {!hasGenerated ? (
                        <button 
                          onClick={() => handleGeneratePreview(index, cut.name)}
                          className="bg-white text-slate-900 px-4 py-2 rounded-full font-bold text-sm flex items-center gap-2 hover:bg-amber-500 transition-colors shadow-lg"
                        >
                          <ImageIcon className="w-4 h-4" />
                          Ver no meu rosto
                        </button>
                      ) : (
                        <button 
                          onClick={() => toggleBeforeAfter(index)}
                          className="bg-slate-900/90 text-white border border-slate-600 px-4 py-2 rounded-full font-bold text-xs flex items-center gap-2 hover:bg-slate-800 transition-colors shadow-lg"
                        >
                          <Layers className="w-3 h-3" />
                          {isShowOriginal ? 'Ver Resultado' : 'Ver Original'}
                        </button>
                      )}
                    </div>
                  )}
                </div>

                <div className="p-6 flex flex-col flex-grow">
                  <h4 className="text-xl font-bold text-white mb-3">{cut.name}</h4>
                  <p className="text-slate-400 text-sm leading-relaxed mb-4 flex-grow">
                    {cut.reason}
                  </p>

                  <div className="pt-4 border-t border-slate-700/50 flex items-center justify-between mt-auto">
                    <span className="text-xs font-mono text-slate-500">Recomendação #{index + 1}</span>
                    <a href="#agendamento" className="text-amber-500 text-sm font-medium hover:underline">
                      Agendar este
                    </a>
                  </div>
                </div>
              </div>
            );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

