import React, { useState, useRef, useEffect } from 'react';
import { Camera, AlertCircle, Loader2, User, RefreshCw, ImageIcon, Filter, Layers, ScanFace, Check, Cpu, Zap, Scissors, Maximize2, X } from 'lucide-react';
import { analyzeHairstyle, generateHairstylePreview } from '../services/geminiService';
import { VisagismAnalysisResult } from '../types';
import { STYLE_PREFERENCES } from '../constants';

const LOADING_STEPS = [
  "Inicializando rede neural...",
  "Mapeando geometria facial...",
  "Analisando terço inferior e queixo...",
  "Calculando simetria e estrutura óssea...",
  "Cruzando dados com base de visagismo...",
  "Renderizando recomendações personalizadas..."
];

export const VisagismFeature: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [loadingStepIndex, setLoadingStepIndex] = useState(0);
  const [result, setResult] = useState<VisagismAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState<string>("Todos");

  // State for image generation
  const [previewImages, setPreviewImages] = useState<Record<number, string>>({});
  const [loadingPreviews, setLoadingPreviews] = useState<Record<number, boolean>>({});
  // State for Before/After toggle (true = show original, false = show generated)
  const [showOriginal, setShowOriginal] = useState<Record<number, boolean>>({});

  // State for Fullscreen Modal
  const [fullscreenIndex, setFullscreenIndex] = useState<number | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Effect to cycle loading messages
  useEffect(() => {
    let interval: any;
    if (loading) {
      setLoadingStepIndex(0);
      // Calculate duration per step based on a roughly fixed total wait time (e.g., 6 seconds total)
      const stepDuration = 1200; 
      interval = setInterval(() => {
        setLoadingStepIndex((prev) => {
          if (prev < LOADING_STEPS.length - 1) return prev + 1;
          return prev;
        });
      }, stepDuration);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      setError("A imagem deve ter no máximo 5MB.");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setImage(reader.result as string);
      setResult(null);
      setError(null);
      setPreviewImages({});
      setShowOriginal({});
      setFullscreenIndex(null);
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!image) return;

    setLoading(true);
    setError(null);

    try {
      const analysis = await analyzeHairstyle(image, selectedStyle);
      setResult(analysis);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Erro ao analisar a imagem. Verifique a API Key ou tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const handleGeneratePreview = async (index: number, cutName: string) => {
    if (!image) return;

    setLoadingPreviews(prev => ({ ...prev, [index]: true }));

    try {
      const generatedImage = await generateHairstylePreview(image, cutName);
      setPreviewImages(prev => ({ ...prev, [index]: generatedImage }));
      setShowOriginal(prev => ({ ...prev, [index]: false })); // Auto-switch to generated
    } catch (err) {
      console.error("Failed to generate preview", err);
      // Optional: Show a toast error here
    } finally {
      setLoadingPreviews(prev => ({ ...prev, [index]: false }));
    }
  };

  const toggleBeforeAfter = (index: number) => {
    setShowOriginal(prev => ({ ...prev, [index]: !prev[index] }));
  };

  const handleReset = () => {
    setImage(null);
    setResult(null);
    setError(null);
    setPreviewImages({});
    setLoadingPreviews({});
    setShowOriginal({});
    setFullscreenIndex(null);
    setSelectedStyle("Todos");
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  return (
    <div id="visagismo" className="max-w-4xl mx-auto py-16 px-6">

      {/* --- SUPERCHARGED FULL SCREEN LOADING OVERLAY --- */}
      {loading && (
        <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col items-center justify-center p-6 overflow-hidden">

          {/* Animated Background Grid */}
          <div className="absolute inset-0 opacity-20 pointer-events-none" 
               style={{ 
                 backgroundImage: 'linear-gradient(rgba(245, 158, 11, 0.1) 1px, transparent 1px), linear-gradient(90deg, rgba(245, 158, 11, 0.1) 1px, transparent 1px)', 
                 backgroundSize: '40px 40px',
                 transform: 'perspective(500px) rotateX(60deg) translateY(-100px) scale(2)'
               }}>
          </div>

          <div className="relative z-10 flex flex-col items-center w-full max-w-lg">

            {/* Orbital Scanner Animation */}
            <div className="relative w-40 h-40 mb-10">
              {/* Core Glow */}
              <div className="absolute inset-0 bg-amber-500/10 rounded-full blur-2xl animate-pulse"></div>

              {/* Outer Ring - Slow Spin */}
              <div className="absolute inset-0 border border-slate-700/50 rounded-full"></div>
              <div className="absolute inset-0 border-t-2 border-r-2 border-amber-500/30 rounded-full animate-[spin_3s_linear_infinite]"></div>

              {/* Middle Ring - Fast Spin Reverse */}
              <div className="absolute inset-4 border-2 border-slate-800 rounded-full"></div>
              <div className="absolute inset-4 border-b-4 border-l-2 border-amber-500 rounded-full animate-[spin_2s_linear_infinite_reverse]"></div>

              {/* Inner Circle - Pulse */}
              <div className="absolute inset-10 bg-slate-900 border border-amber-500/50 rounded-full flex items-center justify-center shadow-[0_0_15px_rgba(245,158,11,0.3)] animate-pulse">
                <ScanFace className="w-10 h-10 text-amber-500" />
              </div>

              {/* Data Points Particles (Decoration) */}
              <div className="absolute top-0 right-0 w-2 h-2 bg-amber-400 rounded-full animate-ping"></div>
              <div className="absolute bottom-2 left-2 w-1.5 h-1.5 bg-amber-600 rounded-full animate-ping delay-700"></div>
            </div>

            <h3 className="text-2xl md:text-4xl font-black text-white text-center mb-1 tracking-tight">
              ANALISANDO TRAÇOS
            </h3>
            <p className="text-amber-500/60 text-xs tracking-[0.2em] mb-8 font-mono">POWERED BY GEMINI AI</p>

            {/* Terminal / Checklist Style Progress */}
            <div className="w-full bg-slate-900/80 border border-slate-800 rounded-lg p-6 font-mono text-sm shadow-2xl backdrop-blur-md">
              <div className="flex flex-col gap-3">
                {LOADING_STEPS.map((step, index) => {
                   const isDone = index < loadingStepIndex;
                   const isCurrent = index === loadingStepIndex;
                   const isPending = index > loadingStepIndex;

                   return (
                     <div key={index} className={`flex items-center gap-3 transition-all duration-300 ${isPending ? 'opacity-30' : 'opacity-100'}`}>
                        <div className="w-5 h-5 flex items-center justify-center">
                          {isDone && <Check className="w-4 h-4 text-green-500" />}
                          {isCurrent && <Loader2 className="w-4 h-4 text-amber-500 animate-spin" />}
                          {isPending && <div className="w-2 h-2 bg-slate-700 rounded-full" />}
                        </div>
                        <span className={`${isCurrent ? 'text-amber-400 font-bold' : isDone ? 'text-slate-400 line-through decoration-slate-600' : 'text-slate-500'}`}>
                          {step}
                        </span>
                     </div>
                   );
                })}
              </div>
            </div>

          </div>
        </div>
      )}

      {/* --- IMAGE FULLSCREEN MODAL --- */}
      {fullscreenIndex !== null && result && (
        <div className="fixed inset-0 z-[200] bg-black/95 backdrop-blur-md flex flex-col items-center justify-center p-4 animate-fade-in" onClick={() => setFullscreenIndex(null)}>
          {/* Close Button */}
