              >
                {/* Dynamic Content Area */}
                <div className="relative w-full aspect-square bg-slate-900 flex items-center justify-center border-b border-slate-700/50 overflow-hidden">

                  {isLoadingThis ? (
                     <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900">
                       {/* Blurred Background Image */}
                       <img src={image!} className="absolute inset-0 w-full h-full object-cover opacity-20 blur-sm" alt="Processing" />

                       {/* LASER SCANNER EFFECT */}
                       <div className="absolute inset-0 w-full h-[4px] bg-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.8)] animate-[scan_1.5s_ease-in-out_infinite] z-30"></div>
