export const IntroOverlay: React.FC = () => {
  const [isVisible, setIsVisible] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const hasSeenIntro = localStorage.getItem('barberflow_intro_seen');
    if (!hasSeenIntro) {
      setIsVisible(true);
      document.body.style.overflow = 'hidden';
    }

    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  // Lógica de Avanço Automático e Barra de Progresso
  useEffect(() => {
    if (!isVisible) return;

    // Se for o último slide, não avança automaticamente (espera clique do usuário)
    if (currentSlide === SLIDES.length - 1) {
      setProgress(100);
      return;
    }

    // Reset progress when slide changes
    setProgress(0);

    const startTime = Date.now();
    const timerInterval = 50; // Update progress every 50ms

    const intervalId = setInterval(() => {
      const elapsed = Date.now() - startTime;
      const newProgress = Math.min((elapsed / AUTO_ADVANCE_DURATION) * 100, 100);
      setProgress(newProgress);

      if (elapsed >= AUTO_ADVANCE_DURATION) {
        setCurrentSlide(prev => prev + 1);
        clearInterval(intervalId);
      }
    }, timerInterval);

    return () => clearInterval(intervalId);
  }, [currentSlide, isVisible]);

  const handleClose = () => {
    setIsVisible(false);
    localStorage.setItem('barberflow_intro_seen', 'true');
    document.body.style.overflow = 'auto';
  };

  const nextSlide = () => {
    if (currentSlide < SLIDES.length - 1) {
      setCurrentSlide(prev => prev + 1);
    } else {
      handleClose();
    }
  };

  const goToSlide = (index: number) => {
    setCurrentSlide(index);
  };

  if (!isVisible) return null;

  return (
    <div className="fixed inset-0 z-[300] flex items-center justify-center animate-fade-in">
      {/* Background Image with Parallax-like feel */}
      <div 
        className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1585747860715-2ba37e788b70?q=80&w=2074&auto=format&fit=crop')] bg-cover bg-center"
      ></div>

      {/* Gradient Overlay that changes based on slide - More transparent now */}
      <div className={`absolute inset-0 bg-gradient-to-br ${SLIDES[currentSlide].bgClass} transition-colors duration-700 backdrop-blur-[2px]`}></div>

      {/* Skip Button */}
      <button 
        onClick={handleClose}
        className="absolute top-6 right-6 text-white/60 hover:text-white bg-black/20 hover:bg-black/40 px-4 py-2 rounded-full backdrop-blur-md flex items-center gap-2 text-sm font-medium z-20 transition-all border border-white/10"
      >
        Pular Intro <X className="w-4 h-4" />
      </button>

      {/* Content Container */}
      <div className="relative z-10 w-full max-w-lg mx-6">
        <div className="bg-slate-900/60 backdrop-blur-xl border border-white/10 rounded-3xl p-8 md:p-12 shadow-2xl overflow-hidden relative">

            {/* Auto-advance Progress Bar */}
            {currentSlide < SLIDES.length - 1 && (
              <div className="absolute top-0 left-0 w-full h-1 bg-white/10">
                <div 
                  className="h-full bg-amber-500 transition-all duration-75 ease-linear"
                  style={{ width: `${progress}%` }}
                />
              </div>
            )}

            {/* Slide Content */}
            <div className="flex flex-col items-center text-center min-h-[300px] justify-center transition-all duration-500 transform">

                <div className="mb-8 p-6 bg-white/5 rounded-full ring-1 ring-white/20 shadow-[0_0_30px_rgba(255,255,255,0.1)] animate-bounce-slow">
                   {SLIDES[currentSlide].icon}
                </div>

                <h2 className="text-3xl md:text-4xl font-bold text-white mb-4 tracking-tight drop-shadow-lg">
                  {SLIDES[currentSlide].title}
                </h2>

                <p className="text-slate-200 text-lg leading-relaxed font-light drop-shadow-md">
                  {SLIDES[currentSlide].description}
                </p>

            </div>

            {/* Navigation & Controls */}
            <div className="flex flex-col gap-8 mt-8">

                {/* Dots Indicator */}
                <div className="flex justify-center gap-2">
                  {SLIDES.map((_, idx) => (
                    <button
                      key={idx}
                      onClick={() => goToSlide(idx)}
                      className={`h-1.5 rounded-full transition-all duration-300 ${
                        idx === currentSlide ? 'w-8 bg-amber-500' : 'w-2 bg-white/30 hover:bg-white/50'
                      }`}
                    />
                  ))}
                </div>

                {/* Main Action Button */}
                <button
                  onClick={nextSlide}
                  className="w-full py-4 bg-amber-500 hover:bg-amber-400 text-slate-900 font-bold rounded-xl text-lg shadow-lg shadow-amber-500/20 transition-all flex items-center justify-center gap-2 group"
                >
                  {currentSlide === SLIDES.length - 1 ? (
                    <>
                      Começar Agora <Sparkles className="w-5 h-5 group-hover:rotate-12 transition-transform" />
                    </>
                  ) : (
                    <>
                      Próximo <ChevronRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                    </>
                  )}
                </button>

            </div>

        </div>

        {/* Footer branding */}
        <p className="text-center text-white/40 text-xs mt-6 font-mono tracking-widest uppercase shadow-black drop-shadow-md">
          BarberFlow System v1.0
        </p>
      </div>
    </div>
  );
};

