import React, { useState, useRef, useEffect } from 'react';
import { Camera, AlertCircle, Loader2, User, RefreshCw, ImageIcon, Filter, Layers, ScanFace, Check, Cpu, Zap, Maximize2, X, Terminal, ShieldCheck } from 'lucide-react';
import { analyzeHairstyle, generateHairstylePreview } from '../services/geminiService';
import { VisagismAnalysisResult } from '../types';
import { STYLE_PREFERENCES } from '../constants';

const LOADING_STEPS = [
  "Inicializando rede neural...",
  "Detectando pontos de referência facial...",
  "Mapeando estrutura óssea (Mandíbula/Zigomático)...",
  "Calculando proporções áureas...",
  "Consultando base de dados de visagismo...",
  "Gerando recomendações personalizadas..."
];

export const VisagismFeature: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);

  // Loading State Expanded
  const [loading, setLoading] = useState(false);
  const [loadingStepIndex, setLoadingStepIndex] = useState(0);
  const [loadingProgress, setLoadingProgress] = useState(0);

  const [result, setResult] = useState<VisagismAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState<string>("Todos");

  // State for image generation
  const [previewImages, setPreviewImages] = useState<Record<number, string>>({});
  const [loadingPreviews, setLoadingPreviews] = useState<Record<number, boolean>>({});
  const [showOriginal, setShowOriginal] = useState<Record<number, boolean>>({});

  const [fullscreenIndex, setFullscreenIndex] = useState<number | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Enhanced Loading Effect
  useEffect(() => {
    let stepInterval: any;
    let progressInterval: any;

    if (loading) {
      setLoadingStepIndex(0);
      setLoadingProgress(0);

      const totalSteps = LOADING_STEPS.length;
      // Total estimated time roughly 6-7 seconds
      const stepDuration = 1200; 

      // Step incrementer
      stepInterval = setInterval(() => {
        setLoadingStepIndex((prev) => {
          if (prev < totalSteps - 1) return prev + 1;
          return prev;
        });
      }, stepDuration);

      // Smooth progress bar incrementer
      progressInterval = setInterval(() => {
        setLoadingProgress((prev) => {
          if (prev >= 99) return 99; // Wait for actual finish
          // Add a random small amount to simulate realistic processing variations
          return prev + (Math.random() * 1.5);
        });
      }, 100);
    }

    return () => {
      clearInterval(stepInterval);
      clearInterval(progressInterval);
    };
  }, [loading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      setError("A imagem deve ter no máximo 5MB.");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setImage(reader.result as string);
      setResult(null);
      setError(null);
      setPreviewImages({});
      setShowOriginal({});
      setFullscreenIndex(null);
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!image) return;

    setLoading(true);
    setError(null);

    try {
      const analysis = await analyzeHairstyle(image, selectedStyle);
      setLoadingProgress(100); // Force complete
      // Small delay to show 100%
      setTimeout(() => {
        setResult(analysis);
        setLoading(false);
      }, 600);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Erro ao analisar a imagem. Verifique a API Key ou tente novamente.");
      setLoading(false);
    }
  };

  const handleGeneratePreview = async (index: number, cutName: string) => {
    if (!image) return;

    setLoadingPreviews(prev => ({ ...prev, [index]: true }));

    try {
      const generatedImage = await generateHairstylePreview(image, cutName);
      setPreviewImages(prev => ({ ...prev, [index]: generatedImage }));
      setShowOriginal(prev => ({ ...prev, [index]: false }));
    } catch (err) {
      console.error("Failed to generate preview", err);
    } finally {
      setLoadingPreviews(prev => ({ ...prev, [index]: false }));
    }
  };

  const toggleBeforeAfter = (index: number) => {
    setShowOriginal(prev => ({ ...prev, [index]: !prev[index] }));
  };

  const handleReset = () => {
    setImage(null);
    setResult(null);
    setError(null);
    setPreviewImages({});
    setLoadingPreviews({});
    setShowOriginal({});
    setFullscreenIndex(null);
    setSelectedStyle("Todos");
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  return (
    <div id="visagismo" className="max-w-4xl mx-auto py-16 px-6">

      {/* --- ULTRA HUD LOADING OVERLAY --- */}
      {loading && (
        <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col items-center justify-center p-6 overflow-hidden">

          {/* Animated Matrix Grid Background */}
          <div className="absolute inset-0 opacity-10 pointer-events-none" 
               style={{ 
                 backgroundImage: 'radial-gradient(circle, #f59e0b 1px, transparent 1px)', 
                 backgroundSize: '30px 30px',
                 animation: 'pulse 4s infinite'
               }}>
          </div>
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-amber-500 to-transparent opacity-50"></div>

          <div className="relative z-10 w-full max-w-2xl flex flex-col md:flex-row gap-10 items-center justify-center">

            {/* LEFT: Biometric Scanner Visual */}
            <div className="relative w-64 h-64 flex-shrink-0">
               {/* Rotating Rings */}
               <div className="absolute inset-0 border border-amber-500/20 rounded-full animate-[spin_10s_linear_infinite]"></div>
               <div className="absolute inset-4 border border-amber-500/10 rounded-full animate-[spin_8s_linear_infinite_reverse]"></div>
               <div className="absolute inset-0 border-t-2 border-amber-500 rounded-full animate-[spin_2s_linear_infinite]"></div>

               {/* Face Wireframe Simulation (SVG) */}
               <div className="absolute inset-0 flex items-center justify-center p-8 opacity-80">
                  <svg viewBox="0 0 100 100" fill="none" stroke="currentColor" className="w-full h-full text-amber-500/50 stroke-1">
                    <path d="M20,30 Q50,5 80,30" /> {/* Forehead */}
                    <path d="M20,30 L20,60 Q20,90 50,95 Q80,90 80,60 L80,30" /> {/* Jaw */}
                    <path d="M35,45 Q50,45 65,45" /> {/* Eyes line */}
                    <path d="M48,50 L48,65" /> {/* Nose */}
                    <path d="M35,75 Q50,80 65,75" /> {/* Mouth */}

                    {/* Scanning Grid inside face */}
                    <path d="M20,40 L80,40" strokeOpacity="0.2" />
                    <path d="M20,50 L80,50" strokeOpacity="0.2" />
                    <path d="M25,60 L75,60" strokeOpacity="0.2" />
                    <path d="M30,70 L70,70" strokeOpacity="0.2" />
                    <path d="M40,20 L40,90" strokeOpacity="0.2" />
                    <path d="M60,20 L60,90" strokeOpacity="0.2" />
                  </svg>
               </div>

               {/* Laser Scan Effect */}
               <div className="absolute inset-0 bg-gradient-to-b from-transparent via-amber-500/30 to-transparent h-[15%] w-full animate-[scan_2s_linear_infinite]"></div>

               {/* Data Points */}
               <div className="absolute top-1/4 left-1/4 w-1 h-1 bg-amber-400 rounded-full animate-ping"></div>
               <div className="absolute bottom-1/3 right-1/3 w-1 h-1 bg-amber-400 rounded-full animate-ping delay-300"></div>
               <div className="absolute top-1/2 right-1/4 w-1 h-1 bg-amber-400 rounded-full animate-ping delay-700"></div>
            </div>

            {/* RIGHT: Data Terminal & Progress */}
            <div className="flex-grow w-full max-w-md">
                <div className="mb-6">
                   <h3 className="text-3xl font-black text-white tracking-tighter mb-1 font-mono">
                     ANALISANDO<span className="animate-pulse">_</span>
                   </h3>
                   <div className="flex justify-between text-xs text-amber-500/80 font-mono uppercase tracking-widest mb-2">
                      <span>Gemini AI Core</span>
                      <span>v1.5.0-flash</span>
                   </div>

                   {/* Progress Bar */}
                   <div className="h-2 w-full bg-slate-800 rounded-full overflow-hidden border border-slate-700">
                      <div 
                        className="h-full bg-amber-500 shadow-[0_0_10px_#f59e0b] transition-all duration-200 ease-out"
                        style={{ width: `${loadingProgress}%` }}
                      ></div>
                   </div>
                   <div className="text-right text-white font-mono font-bold mt-1">
                      {Math.floor(loadingProgress)}%
                   </div>
                </div>

                {/* Terminal Log */}
                <div className="bg-slate-900/80 border border-slate-700 rounded-lg p-4 font-mono text-xs md:text-sm shadow-xl h-48 overflow-hidden relative">
                   <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-green-500 via-emerald-400 to-green-600 opacity-50"></div>

                   <div className="flex flex-col gap-3 h-full justify-end pb-2">
                      {LOADING_STEPS.map((step, index) => {
                        const isDone = index < loadingStepIndex;
                        const isCurrent = index === loadingStepIndex;
                        const isPending = index > loadingStepIndex;

                        if (isPending) return null; // Don't show pending steps yet to look like real-time log

                        return (
                          <div key={index} className={`flex items-start gap-3 animate-fade-in-left`}>
                              <span className="text-slate-500 shrink-0">
                                {`[${String(index + 1).padStart(2, '0')}]`}
                              </span>
                              <div className="flex-grow">
                                <span className={`${isCurrent ? 'text-amber-400' : 'text-green-400/80'}`}>
                                  {step}
                                </span>
                                {isCurrent && (
                                  <span className="inline-block w-2 h-4 bg-amber-500 ml-1 animate-pulse align-middle"></span>
                                )}
                              </div>
                              {isDone && <Check className="w-3 h-3 text-green-500 mt-1" />}
                          </div>
                        );
                      })}
                   </div>

                   {/* Scanlines overlay on terminal */}
                   <div className="absolute inset-0 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%] pointer-events-none"></div>
                </div>
            </div>

          </div>
        </div>
      )}

      {/* --- IMAGE FULLSCREEN MODAL --- */}
      {fullscreenIndex !== null && result && (
        <div className="fixed inset-0 z-[200] bg-black/95 backdrop-blur-md flex flex-col items-center justify-center p-4 animate-fade-in" onClick={() => setFullscreenIndex(null)}>
          {/* Close Button */}
          <button
            onClick={() => setFullscreenIndex(null)}
            className="absolute top-6 right-6 text-white/70 hover:text-white bg-white/10 hover:bg-white/20 p-3 rounded-full transition-all z-[210]"
          >
            <X className="w-8 h-8" />
          </button>

          {/* Content Container */}
          <div 
            className="relative w-full max-w-6xl h-full max-h-[90vh] flex flex-col items-center justify-center"
            onClick={(e) => e.stopPropagation()} // Prevent closing when clicking content
          >
              {(() => {
                 const hasGenerated = !!previewImages[fullscreenIndex];
                 const isShowOriginal = showOriginal[fullscreenIndex];
                 const displayImage = (hasGenerated && !isShowOriginal) ? previewImages[fullscreenIndex] : image!;
                 const cut = result.suggestedCuts[fullscreenIndex];

                 return (
                   <>
                     <img
                       src={displayImage}
                       alt={cut.name}
                       className="w-auto h-auto max-w-full max-h-full object-contain rounded-lg shadow-2xl shadow-black border border-slate-800"
                     />

                     {/* Controls Overlay */}
                     <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-slate-900/90 backdrop-blur-xl px-6 py-4 rounded-full border border-slate-700 shadow-2xl">
                        <span className="text-white font-bold whitespace-nowrap text-lg hidden sm:block">{cut.name}</span>
                        <div className="h-6 w-px bg-slate-600 hidden sm:block"></div>

                        {/* Toggle Button */}
                        {hasGenerated && (
                           <button
                              onClick={() => toggleBeforeAfter(fullscreenIndex)}
                              className="flex items-center gap-2 text-sm font-bold text-amber-500 hover:text-amber-300 transition-colors uppercase tracking-wide"
                           >
                              <Layers className="w-5 h-5" />
                              {isShowOriginal ? "Ver Simulação" : "Ver Original"}
                           </button>
                        )}
                        {!hasGenerated && (
                           <span className="text-slate-400 text-sm">Simulação não gerada</span>
                        )}
                     </div>
                   </>
                 )
              })()}
          </div>
        </div>
      )}


      <div className="text-center mb-12">
        <h3 className="text-amber-500 font-bold uppercase tracking-wider text-sm mb-2 flex items-center justify-center gap-2">
           <Zap className="w-4 h-4" /> Feature Premium
        </h3>
        <h2 className="text-3xl md:text-4xl font-bold text-white mb-4">Visagismo com IA</h2>
        <p className="text-slate-400 max-w-2xl mx-auto">
          Envie uma selfie e nossa Inteligência Artificial analisará seu formato de rosto para recomendar os cortes que mais valorizam seus traços.
        </p>
      </div>

      {/* Upload Section */}
      {!result && (
        <div className="bg-slate-800/50 border border-slate-700 rounded-2xl p-8 backdrop-blur-sm relative overflow-hidden group">
          {/* Subtle animated border gradient */}
          <div className="absolute inset-0 bg-gradient-to-r from-transparent via-slate-700/20 to-transparent translate-x-[-100%] group-hover:animate-[shimmer_2s_infinite] pointer-events-none"></div>

          {!image ? (
            <div 
              className="border-2 border-dashed border-slate-600 rounded-xl p-12 text-center cursor-pointer hover:border-amber-500 hover:bg-slate-800 transition-all duration-300 relative"
              onClick={() => fileInputRef.current?.click()}
            >
              <div className="w-20 h-20 bg-slate-700/50 rounded-full flex items-center justify-center mx-auto mb-6 group-hover:scale-110 group-hover:bg-amber-500/10 transition-all duration-300">
                <Camera className="w-10 h-10 text-slate-400 group-hover:text-amber-500 transition-colors" />
              </div>
              <h4 className="text-xl font-semibold text-white mb-2">Tire uma selfie ou envie uma foto</h4>
              <p className="text-slate-400 text-sm mb-6">Formatos: JPG, PNG (Max 5MB)</p>
              <button className="bg-slate-700 text-white px-8 py-3 rounded-full font-medium text-sm group-hover:bg-amber-600 transition-all hover:shadow-lg hover:shadow-amber-500/20">
                Selecionar Arquivo
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                accept="image/*" 
                className="hidden" 
              />
            </div>
          ) : (
            <div className="flex flex-col items-center">
              <div className="relative w-64 h-64 mb-6 rounded-xl overflow-hidden border-4 border-slate-700 shadow-2xl group/img">
                <img src={image} alt="Upload" className="w-full h-full object-cover transition-transform duration-700 group-hover/img:scale-105" />
                <button 
                  onClick={handleReset}
                  className="absolute top-2 right-2 bg-black/60 text-white p-2 rounded-full hover:bg-red-500 transition-colors backdrop-blur-md"
                >
                  <RefreshCw className="w-4 h-4" />
                </button>
              </div>

              {/* Style Preference Filter */}
              <div className="w-full max-w-xl mb-8 animate-fade-in-up">
                  <div className="flex items-center gap-2 mb-3 justify-center text-slate-300">
                    <Filter className="w-4 h-4 text-amber-500" />
                    <span className="text-sm font-medium">Filtrar estilo preferido (Opcional)</span>
                  </div>
                  <div className="flex flex-wrap justify-center gap-2">
                    {STYLE_PREFERENCES.map((style) => (
                      <button
                        key={style}
                        onClick={() => setSelectedStyle(style)}
                        className={`
                          px-4 py-2 rounded-full text-xs font-medium transition-all duration-300
                          ${selectedStyle === style 
                            ? 'bg-amber-500 text-slate-900 shadow-lg shadow-amber-500/20 scale-105' 
                            : 'bg-slate-700 text-slate-300 hover:bg-slate-600 hover:text-white'
                          }
                        `}
                      >
                        {style}
                      </button>
                    ))}
                  </div>
              </div>

              {error && (
                <div className="bg-red-500/10 border border-red-500/50 text-red-200 px-4 py-3 rounded-lg flex items-center gap-2 mb-6 max-w-md w-full animate-shake">
                  <AlertCircle className="w-5 h-5 flex-shrink-0" />
                  <p className="text-sm">{error}</p>
                </div>
              )}

              <button
                onClick={handleAnalyze}
                disabled={loading}
                className={`
                  w-full max-w-sm py-4 px-6 rounded-xl font-bold text-lg flex items-center justify-center gap-3 shadow-xl
                  ${loading 
                    ? 'bg-slate-700 text-slate-400 cursor-not-allowed' 
                    : 'bg-gradient-to-r from-amber-500 to-amber-600 text-slate-900 hover:scale-[1.02] hover:shadow-amber-500/25'
                  } transition-all duration-300
                `}
              >
                  <>
                    <Cpu className="w-6 h-6" />
                    Iniciar Análise IA
                  </>
              </button>
            </div>
          )}
        </div>
      )}

      {/* Results Section */}
      {result && (
        <div className="animate-fade-in">
          <div className="bg-slate-800 rounded-2xl p-8 border border-slate-700 mb-8 flex flex-col md:flex-row gap-8 items-center md:items-start relative overflow-hidden">
             {/* Decorative background accent */}
             <div className="absolute -top-20 -right-20 w-64 h-64 bg-amber-500/5 rounded-full blur-3xl"></div>

            <div className="w-32 h-32 rounded-full border-4 border-amber-500 flex items-center justify-center bg-slate-900 flex-shrink-0 shadow-xl shadow-amber-900/20 relative z-10">
              <User className="w-16 h-16 text-amber-500" />
            </div>
            <div className="text-center md:text-left relative z-10">
              <h3 className="text-slate-400 text-sm font-medium uppercase tracking-wide mb-1 flex items-center justify-center md:justify-start gap-2">
                 <ShieldCheck className="w-4 h-4 text-green-500" />
                 Análise de Visagismo Concluída
              </h3>
              <h2 className="text-3xl font-bold text-white mb-2">
                Seu rosto é <span className="text-transparent bg-clip-text bg-gradient-to-r from-amber-400 to-amber-200">{result.faceShape}</span>
              </h2>
              <div className="flex flex-col gap-2">
                 <p className="text-slate-300 max-w-lg">
                  Para este formato, a IA selecionou estilos que harmonizam a geometria facial, 
                  valorizando seus pontos fortes.
                </p>
                {selectedStyle !== "Todos" && (
                  <p className="text-amber-500/80 text-sm italic">
                    *Filtro ativo: {selectedStyle}
                  </p>
                )}
              </div>
            </div>
            <div className="md:ml-auto relative z-10">
               <button 
                onClick={handleReset} 
                className="text-sm text-slate-400 hover:text-white underline decoration-amber-500/50 hover:decoration-amber-500 underline-offset-4 transition-all"
              >
                Refazer análise
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {result.suggestedCuts.map((cut, index) => {
              const hasGenerated = !!previewImages[index];
              const isShowOriginal = showOriginal[index];
              const isLoadingThis = loadingPreviews[index];
              const displayImage = (hasGenerated && !isShowOriginal) ? previewImages[index] : image!;

              return (
              <div 
                key={index} 
                className="bg-slate-800 border border-slate-700 rounded-xl overflow-hidden hover:border-amber-500/50 hover:bg-slate-800/80 transition-all duration-300 group flex flex-col hover:shadow-2xl hover:shadow-black/50"
              >
                {/* Dynamic Content Area */}
                <div className="relative w-full aspect-square bg-slate-900 flex items-center justify-center border-b border-slate-700/50 overflow-hidden">

                  {isLoadingThis ? (
                     <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900">
                       {/* Blurred Background Image */}
                       <img src={image!} className="absolute inset-0 w-full h-full object-cover opacity-20 blur-sm" alt="Processing" />

                       {/* LASER SCANNER EFFECT */}
                       <div className="absolute inset-0 w-full h-[4px] bg-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.8)] animate-[scan_1.5s_ease-in-out_infinite] z-30"></div>
                       <div className="absolute inset-0 bg-gradient-to-b from-amber-500/10 to-transparent animate-[scan_1.5s_ease-in-out_infinite] z-20"></div>

                       <div className="relative z-40 bg-slate-900/80 backdrop-blur px-4 py-2 rounded-full border border-amber-500/30 flex items-center gap-2">
                         <Loader2 className="w-4 h-4 animate-spin text-amber-500" />
                         <span className="text-xs font-mono text-amber-400">GERANDO...</span>
                       </div>
                     </div>
                  ) : hasGenerated || isShowOriginal ? (
                     <>
                        <img 
                          src={displayImage} 
                          alt={`Visualização ${cut.name}`} 
                          className="w-full h-full object-cover animate-fade-in transition-transform duration-700 hover:scale-105 cursor-pointer"
                          onClick={() => setFullscreenIndex(index)}
                        />
                        {/* Before/After Toggle Badge */}
                        <div className="absolute top-3 left-3 z-10 pointer-events-none">
                           <span className={`text-[10px] font-bold px-3 py-1.5 rounded-full backdrop-blur-md shadow-lg border ${isShowOriginal ? 'bg-slate-900/60 text-white border-slate-600' : 'bg-amber-500/90 text-slate-900 border-amber-400'}`}>
                              {isShowOriginal ? 'FOTO ORIGINAL' : 'SIMULAÇÃO IA'}
                           </span>
                        </div>

                        {/* Fullscreen Button */}
                        <button
                          onClick={(e) => {
                             e.stopPropagation();
                             setFullscreenIndex(index);
                          }}
                          className="absolute top-3 right-3 z-20 p-2 bg-black/40 hover:bg-black/60 text-white rounded-full backdrop-blur-md transition-all opacity-0 group-hover:opacity-100 scale-90 hover:scale-100"
                          title="Tela Cheia"
                        >
                           <Maximize2 className="w-4 h-4" />
                        </button>
                     </>
                  ) : (
                    <div className="flex flex-col items-center gap-3">
                      <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center text-slate-600 mb-2 group-hover:bg-amber-500/10 group-hover:text-amber-500 transition-all duration-500">
                        <ScissorsIcon className="w-10 h-10" />
                      </div>
                      <p className="text-xs text-slate-500 font-medium">Visualização não gerada</p>
                    </div>
                  )}

                  {/* Action Buttons Overlay */}
                  {!isLoadingThis && (
                    <div className={`absolute bottom-0 w-full p-4 flex justify-center gap-2 z-20 ${hasGenerated ? 'bg-gradient-to-t from-black/90 via-black/50 to-transparent pt-12' : 'bg-black/40 opacity-0 group-hover:opacity-100 backdrop-blur-[2px]'} transition-all duration-300`}>

                      {!hasGenerated ? (
                        <button 
                          onClick={() => handleGeneratePreview(index, cut.name)}
                          className="bg-white hover:bg-amber-400 text-slate-900 px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2 transition-all shadow-lg hover:shadow-amber-500/50 transform hover:scale-105"
                        >
                          <ImageIcon className="w-4 h-4" />
                          Ver no meu rosto
                        </button>
                      ) : (
                        <button 
                          onClick={() => toggleBeforeAfter(index)}
                          className="bg-slate-800/90 text-white hover:bg-slate-700 border border-slate-600 px-5 py-2 rounded-full font-bold text-xs flex items-center gap-2 transition-all shadow-lg backdrop-blur-md"
                        >
                          <Layers className="w-3 h-3" />
                          {isShowOriginal ? 'Ver Resultado' : 'Ver Original'}
                        </button>
                      )}
                    </div>
                  )}
                </div>

                <div className="p-6 flex flex-col flex-grow relative bg-slate-800">
                  <h4 className="text-xl font-bold text-white mb-3 group-hover:text-amber-400 transition-colors">{cut.name}</h4>
                  <p className="text-slate-400 text-sm leading-relaxed mb-4 flex-grow border-l-2 border-slate-700 pl-3">
                    {cut.reason}
                  </p>

                  <div className="pt-4 border-t border-slate-700/50 flex items-center justify-between mt-auto">
                    <span className="text-xs font-mono text-slate-500 bg-slate-900 px-2 py-1 rounded">#{index + 1}</span>
                    <a href="#agendamento" className="text-amber-500 text-sm font-bold hover:text-amber-300 flex items-center gap-1 group/link">
                      Agendar este corte 
                      <span className="group-hover/link:translate-x-1 transition-transform">→</span>
                    </a>
                  </div>
                </div>
              </div>
            );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

// Helper component for the scissors icon
const ScissorsIcon = ({ className }: { className?: string }) => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <circle cx="6" cy="6" r="3"></circle>
    <circle cx="6" cy="18" r="3"></circle>
    <line x1="20" y1="4" x2="8.12" y2="15.88"></line>
    <line x1="14.47" y1="14.48" x2="20" y2="20"></line>
    <line x1="8.12" y1="8.12" x2="12" y2="12"></line>
  </svg>
);

import React, { useState, useEffect } from 'react';
import { backendService } from '../services/backendService';
import { Barber, TimeSlot } from '../types';
import { Calendar as CalendarIcon, Clock, Check, UserIcon, Smartphone, X, ChevronRight, Loader2 } from 'lucide-react';

export const Scheduling: React.FC = () => {
  // Data State
  const [barbers, setBarbers] = useState<Barber[]>([]);
  const [availableSlots, setAvailableSlots] = useState<TimeSlot[]>([]);

  // Selection State
  const [selectedBarber, setSelectedBarber] = useState<Barber | null>(null);
  const [selectedDate, setSelectedDate] = useState<string>("");
  const [selectedSlot, setSelectedSlot] = useState<TimeSlot | null>(null);

  // UI State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({ name: '', phone: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Initialize Data
  useEffect(() => {
    setBarbers(backendService.getBarbers());
    // Default to today's date
    const today = new Date().toISOString().split('T')[0];
    setSelectedDate(today);
  }, []);

  // Update slots when Barber or Date changes
  useEffect(() => {
    if (selectedBarber && selectedDate) {
      const slots = backendService.getAvailableSlots(selectedBarber.id, selectedDate);
      setAvailableSlots(slots);
      setSelectedSlot(null); // Reset slot selection
    } else {
      setAvailableSlots([]);
    }
  }, [selectedBarber, selectedDate]);

  const handleOpenModal = () => {
    if (selectedBarber && selectedSlot && selectedDate) {
      setIsModalOpen(true);
    }
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setFormData({ name: '', phone: '' });
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleConfirmBooking = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBarber || !selectedSlot || !selectedDate) return;

    setIsSubmitting(true);

    try {
      // 1. Save to internal "Backend"
      backendService.createAppointment({
        barberId: selectedBarber.id,
        barberName: selectedBarber.name,
        clientName: formData.name,
        clientPhone: formData.phone,
        date: selectedDate,
        time: selectedSlot.time
      });

      // 2. Refresh slots to show it's taken (if user stays on page)
      const slots = backendService.getAvailableSlots(selectedBarber.id, selectedDate);
      setAvailableSlots(slots);

      // 3. Create WhatsApp Link
      const businessPhone = "5511999999999"; 
      // Format date for display
      const dateDisplay = new Date(selectedDate).toLocaleDateString('pt-BR');
      const message = `Olá! Me chamo *${formData.name}*. Acabei de agendar no site com *${selectedBarber.name}* para dia *${dateDisplay}* às *${selectedSlot.time}*.`;
      const whatsappUrl = `https://wa.me/${businessPhone}?text=${encodeURIComponent(message)}`;

      setTimeout(() => {
        window.open(whatsappUrl, '_blank');
        setIsSubmitting(false);
        setIsModalOpen(false);

        // Reset major selections to prevent double booking easily
        setSelectedSlot(null);
        alert("Agendamento confirmado com sucesso!");
      }, 800);

    } catch (error: any) {
      alert(error.message);
      setIsSubmitting(false);
    }
  };

  return (
    <div id="agendamento" className="py-16 px-6 bg-slate-900/50">
      <div className="max-w-4xl mx-auto">
        <div className="text-center mb-12">
          <h2 className="text-3xl font-bold text-white mb-4">Agende seu Horário</h2>
          <p className="text-slate-400">Escolha seu profissional preferido, data e o melhor momento.</p>
        </div>

        <div className="grid md:grid-cols-2 gap-8">
          {/* Barber Selection */}
          <div className="bg-slate-800 rounded-2xl p-6 border border-slate-700">
            <h3 className="text-xl font-semibold text-white mb-6 flex items-center gap-2">
              <UserIcon className="w-5 h-5 text-amber-500" />
              1. Escolha o Profissional
            </h3>
            <div className="space-y-4">
              {barbers.length === 0 ? (
                 <p className="text-slate-500 text-sm">Nenhum profissional cadastrado.</p>
              ) : (
                barbers.map((barber) => (
                  <div 
                    key={barber.id}
                    onClick={() => setSelectedBarber(barber)}
                    className={`flex items-center gap-4 p-4 rounded-xl cursor-pointer transition-all border ${
                      selectedBarber?.id === barber.id 
                        ? 'bg-amber-500/10 border-amber-500' 
                        : 'bg-slate-700/30 border-slate-700 hover:border-slate-500'
                    }`}
                  >
                    <img src={barber.avatar} alt={barber.name} className="w-12 h-12 rounded-full object-cover" />
                    <div>
                      <p className={`font-medium ${selectedBarber?.id === barber.id ? 'text-amber-500' : 'text-slate-200'}`}>
                        {barber.name}
                      </p>
                      <p className="text-xs text-slate-400">{barber.specialty}</p>
                    </div>
                    {selectedBarber?.id === barber.id && (
                      <Check className="w-5 h-5 text-amber-500 ml-auto" />
                    )}
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Date & Time Selection */}
          <div className="flex flex-col gap-6">

            {/* Date Picker */}
            <div className="bg-slate-800 rounded-2xl p-6 border border-slate-700">
               <h3 className="text-xl font-semibold text-white mb-4 flex items-center gap-2">
                  <CalendarIcon className="w-5 h-5 text-amber-500" />
                  2. Escolha a Data
               </h3>
               <input 
                  type="date" 
                  value={selectedDate}
                  min={new Date().toISOString().split('T')[0]}
                  onChange={(e) => setSelectedDate(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 text-white focus:border-amber-500 focus:outline-none uppercase tracking-wider"
               />
            </div>

            {/* Slots Grid */}
            <div className="bg-slate-800 rounded-2xl p-6 border border-slate-700 flex flex-col flex-grow">
              <h3 className="text-xl font-semibold text-white mb-6 flex items-center gap-2">
                <Clock className="w-5 h-5 text-amber-500" />
                3. Escolha o Horário
              </h3>

              {!selectedBarber ? (
                <div className="flex-grow flex items-center justify-center text-slate-500 text-sm">
                   Selecione um barbeiro primeiro.
                </div>
              ) : (
                <div className="grid grid-cols-3 gap-3">
                  {availableSlots.map((slot, idx) => (
                    <button
                      key={idx}
                      disabled={!slot.available}
                      onClick={() => setSelectedSlot(slot)}
                      className={`
                        py-2 px-3 rounded-lg text-sm font-medium transition-all
                        ${!slot.available 
                          ? 'bg-slate-700/50 text-slate-600 cursor-not-allowed line-through' 
                          : selectedSlot === slot
                            ? 'bg-amber-500 text-slate-900'
                            : 'bg-slate-700 text-slate-300 hover:bg-slate-600'
                        }
                      `}
                    >
                      {slot.time}
                    </button>
                  ))}
                  {availableSlots.length === 0 && (
                     <div className="col-span-3 text-center text-slate-500 text-sm py-4">
                        Nenhum horário disponível nesta data.
                     </div>
                  )}
                </div>
              )}

              <div className="mt-auto pt-8 border-t border-slate-700">
                <button 
                  disabled={!selectedBarber || !selectedSlot || !selectedDate}
                  onClick={handleOpenModal}
                  className={`
                    w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2
                    ${(!selectedBarber || !selectedSlot || !selectedDate)
                      ? 'bg-slate-700 text-slate-500 cursor-not-allowed'
                      : 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-900/20'
                    } transition-all
                  `}
                >
                  Confirmar Agendamento <ChevronRight className="w-4 h-4" />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Booking Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm animate-fade-in">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-md shadow-2xl relative overflow-hidden">

             {/* Header */}
             <div className="bg-slate-800 p-6 border-b border-slate-700 flex justify-between items-center">
                <h3 className="text-xl font-bold text-white">Finalizar Agendamento</h3>
                <button onClick={handleCloseModal} className="text-slate-400 hover:text-white">
                  <X className="w-5 h-5" />
                </button>
             </div>

             {/* Body */}
             <form onSubmit={handleConfirmBooking} className="p-6 space-y-4">

                {/* Summary Card */}
                <div className="bg-slate-800/50 rounded-lg p-4 flex items-center gap-4 mb-4">
                   <div className="bg-amber-500/10 p-2 rounded-full">
                      <CalendarIcon className="w-6 h-6 text-amber-500" />
                   </div>
                   <div>
                      <p className="text-slate-400 text-xs uppercase font-semibold">Resumo</p>
                      <p className="text-white font-medium">{selectedBarber?.name}</p>
                      <p className="text-amber-500 text-sm">
                        {new Date(selectedDate).toLocaleDateString('pt-BR')} às {selectedSlot?.time}
                      </p>
                   </div>
                </div>

                <div>
                   <label className="block text-sm font-medium text-slate-300 mb-1">Seu Nome</label>
                   <div className="relative">
                      <UserIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
                      <input 
                        type="text" 
                        name="name"
                        required
                        value={formData.name}
                        onChange={handleInputChange}
                        placeholder="Ex: João Silva"
                        className="w-full bg-slate-800 border border-slate-700 rounded-lg py-2.5 pl-10 pr-4 text-white placeholder-slate-500 focus:outline-none focus:border-amber-500 focus:ring-1 focus:ring-amber-500 transition-all"
                      />
                   </div>
                </div>

                <div>
                   <label className="block text-sm font-medium text-slate-300 mb-1">WhatsApp</label>
                   <div className="relative">
                      <Smartphone className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
                      <input 
                        type="tel" 
                        name="phone"
                        required
                        value={formData.phone}
                        onChange={handleInputChange}
                        placeholder="(11) 99999-9999"
                        className="w-full bg-slate-800 border border-slate-700 rounded-lg py-2.5 pl-10 pr-4 text-white placeholder-slate-500 focus:outline-none focus:border-amber-500 focus:ring-1 focus:ring-amber-500 transition-all"
                      />
                   </div>
                </div>

                <div className="pt-4">
                  <button 
