export const IntroOverlay: React.FC = () => {
  const [isVisible, setIsVisible] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const hasSeenIntro = localStorage.getItem('barberflow_intro_seen');
    if (!hasSeenIntro) {
      setIsVisible(true);
      document.body.style.overflow = 'hidden';
    }

    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  // Lógica de Avanço Automático
  useEffect(() => {
    if (!isVisible) return;

    if (currentSlide === SLIDES.length - 1) {
      setProgress(100);
      return;
    }

    setProgress(0);
    const startTime = Date.now();
    const intervalId = setInterval(() => {
      const elapsed = Date.now() - startTime;
      const newProgress = Math.min((elapsed / AUTO_ADVANCE_DURATION) * 100, 100);
      setProgress(newProgress);

      if (elapsed >= AUTO_ADVANCE_DURATION) {
        setCurrentSlide(prev => prev + 1);
        clearInterval(intervalId);
      }
    }, 50);

    return () => clearInterval(intervalId);
  }, [currentSlide, isVisible]);

  const handleClose = () => {
    setIsVisible(false);
    localStorage.setItem('barberflow_intro_seen', 'true');
    document.body.style.overflow = 'auto';
  };

  const nextSlide = () => {
    if (currentSlide < SLIDES.length - 1) {
      setCurrentSlide(prev => prev + 1);
    } else {
      handleClose();
    }
  };

  if (!isVisible) return null;

  const activeSlide = SLIDES[currentSlide];
  const isLimeTheme = activeSlide.theme === 'lime';

  return (
    <div className={`fixed inset-0 z-[300] flex flex-col items-center justify-between p-6 transition-colors duration-700 ${isLimeTheme ? 'bg-lime-400' : 'bg-[#0f1115]'}`}>

      {/* Background Ambience for Dark Theme */}
      {!isLimeTheme && (
         <div className="absolute inset-0 overflow-hidden pointer-events-none">
            <div className="absolute top-[-20%] left-[-20%] w-[80%] h-[80%] bg-lime-400/10 blur-[150px] rounded-full"></div>
         </div>
      )}

      {/* Progress Bars Top */}
      <div className="w-full flex gap-2 z-20 pt-4 max-w-md mx-auto">
        {SLIDES.map((_, idx) => (
          <div key={idx} className="h-1.5 rounded-full flex-1 bg-black/10 overflow-hidden relative">
            <div 
               className={`absolute top-0 left-0 h-full transition-all duration-100 ease-linear ${isLimeTheme ? 'bg-black' : 'bg-lime-400'}`}
               style={{ 
                 width: idx < currentSlide ? '100%' : idx === currentSlide ? `${progress}%` : '0%' 
               }}
            />
          </div>
        ))}
      </div>

      {/* Close Button */}
      <button 
        onClick={handleClose}
        className={`absolute top-12 right-6 z-20 p-2 rounded-full font-bold text-sm transition-all font-sans uppercase tracking-wider ${isLimeTheme ? 'text-black hover:bg-black/10' : 'text-white/50 hover:text-white hover:bg-white/10'}`}
      >
        Pular
      </button>

      {/* Main Content */}
      <div className="flex-1 flex flex-col justify-center items-center text-center max-w-sm mx-auto z-10 animate-fade-in-up">

         <div className={`w-24 h-24 rounded-[32px] flex items-center justify-center mb-10 shadow-2xl ${isLimeTheme ? 'bg-black text-lime-400' : 'bg-[#1c1c1e] border border-white/10'}`}>
            {activeSlide.icon}
         </div>

         <span className={`text-sm font-bold tracking-[0.2em] uppercase mb-4 font-sans ${isLimeTheme ? 'text-black/60' : 'text-lime-400'}`}>
            {activeSlide.subtitle}
         </span>

         <h2 className={`text-6xl font-display font-thin uppercase mb-6 leading-[0.85] tracking-tight ${isLimeTheme ? 'text-black' : 'text-white'}`}>
            {activeSlide.title}
         </h2>

         <p className={`text-lg font-medium leading-relaxed font-sans ${isLimeTheme ? 'text-black/70' : 'text-slate-400'}`}>
            {activeSlide.description}
         </p>
      </div>

      {/* Footer Action */}
      <div className="w-full max-w-sm mx-auto z-20 pb-8">
        <button
          onClick={nextSlide}
          className={`w-full py-5 rounded-full font-bold text-lg flex items-center justify-center gap-2 transition-all shadow-xl hover:scale-[1.02] active:scale-[0.98] font-sans uppercase tracking-wide
            ${isLimeTheme 
              ? 'bg-black text-white hover:bg-black/90' 
              : 'bg-lime-400 text-black hover:bg-lime-300 shadow-lime-400/20'
            }`}
        >
          {currentSlide === SLIDES.length - 1 ? "Começar Agora" : "Continuar"}
          {currentSlide === SLIDES.length - 1 ? <Sparkles className="w-5 h-5" /> : <ArrowRight className="w-5 h-5" />}
        </button>
      </div>

    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, AlertCircle, Loader2, User, RefreshCw, ImageIcon, Filter, Layers, ScanFace, Check, Cpu, Zap, Maximize2, X, Terminal, ShieldCheck } from 'lucide-react';
import { analyzeHairstyle, generateHairstylePreview } from '../services/geminiService';
import { VisagismAnalysisResult } from '../types';
import { STYLE_PREFERENCES } from '../constants';

const LOADING_STEPS = [
  "Inicializando rede neural...",
  "Detectando pontos de referência facial...",
  "Mapeando estrutura óssea (Mandíbula/Zigomático)...",
  "Calculando proporções áureas...",
  "Consultando base de dados de visagismo...",
  "Gerando recomendações personalizadas..."
];

export const VisagismFeature: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);

  // Loading State Expanded
  const [loading, setLoading] = useState(false);
  const [loadingStepIndex, setLoadingStepIndex] = useState(0);
  const [loadingProgress, setLoadingProgress] = useState(0);

  const [result, setResult] = useState<VisagismAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState<string>("Todos");

  // State for image generation
  const [previewImages, setPreviewImages] = useState<Record<number, string>>({});
  const [loadingPreviews, setLoadingPreviews] = useState<Record<number, boolean>>({});
  const [showOriginal, setShowOriginal] = useState<Record<number, boolean>>({});

  const [fullscreenIndex, setFullscreenIndex] = useState<number | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Enhanced Loading Effect
  useEffect(() => {
    let stepInterval: any;
    let progressInterval: any;

    if (loading) {
      setLoadingStepIndex(0);
      setLoadingProgress(0);

      const totalSteps = LOADING_STEPS.length;
      // Total estimated time roughly 6-7 seconds
      const stepDuration = 1200; 

      // Step incrementer
      stepInterval = setInterval(() => {
        setLoadingStepIndex((prev) => {
          if (prev < totalSteps - 1) return prev + 1;
          return prev;
        });
      }, stepDuration);

      // Smooth progress bar incrementer
      progressInterval = setInterval(() => {
        setLoadingProgress((prev) => {
          if (prev >= 99) return 99; // Wait for actual finish
          // Add a random small amount to simulate realistic processing variations
          return prev + (Math.random() * 1.5);
        });
      }, 100);
    }

    return () => {
      clearInterval(stepInterval);
      clearInterval(progressInterval);
    };
  }, [loading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      setError("A imagem deve ter no máximo 5MB.");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setImage(reader.result as string);
      setResult(null);
      setError(null);
      setPreviewImages({});
      setShowOriginal({});
      setFullscreenIndex(null);
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!image) return;

    setLoading(true);
    setError(null);

    try {
      const analysis = await analyzeHairstyle(image, selectedStyle);
      setLoadingProgress(100); // Force complete
      // Small delay to show 100%
      setTimeout(() => {
        setResult(analysis);
        setLoading(false);
      }, 600);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Erro ao analisar a imagem. Verifique a API Key ou tente novamente.");
      setLoading(false);
    }
  };

  const handleGeneratePreview = async (index: number, cutName: string) => {
    if (!image) return;

    setLoadingPreviews(prev => ({ ...prev, [index]: true }));

    try {
      const generatedImage = await generateHairstylePreview(image, cutName);
      setPreviewImages(prev => ({ ...prev, [index]: generatedImage }));
      setShowOriginal(prev => ({ ...prev, [index]: false }));
    } catch (err: any) {
      console.error("Failed to generate preview", err);
      // Show user-friendly alert since we don't have a global error state for previews
      alert(err.message || "Não foi possível gerar a simulação neste momento. (Erro de API/Cota)");
    } finally {
      setLoadingPreviews(prev => ({ ...prev, [index]: false }));
    }
  };

