        <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 border border-white/10 mb-8 animate-fade-in">
           <span className="w-2 h-2 rounded-full bg-lime-400 animate-pulse"></span>
           <span className="text-xs font-semibold text-slate-300 tracking-widest uppercase font-sans">Nova IA 2.0 Disponível</span>
        </div>

        <h2 className="text-6xl md:text-8xl font-display font-thin text-white mb-8 leading-[0.9] tracking-tighter uppercase min-h-[300px] md:min-h-[auto]">
          O corte perfeito <br />
          <span className="relative inline-block">
            <span className="relative z-10 text-transparent bg-clip-text bg-gradient-to-r from-lime-300 to-lime-500 font-light">
              {text}
            </span>
            <span className="inline-block w-1.5 h-[0.75em] align-middle bg-lime-400 ml-2 animate-pulse mb-2 md:mb-4"></span>

