            </div>

            {/* RIGHT: Data Terminal & Progress */}
            <div className="flex-grow w-full max-w-md">
                <div className="mb-8">
                   <h3 className="text-5xl font-display font-thin uppercase tracking-tighter mb-2 text-white">
