import React, { useState, useEffect } from 'react';
import { backendService } from '../services/backendService';
import { Barber, TimeSlot } from '../types';
import { Calendar as CalendarIcon, Clock, Check, UserIcon, Smartphone, X, ChevronRight, Loader2 } from 'lucide-react';

export const Scheduling: React.FC = () => {
  // Data State
  const [barbers, setBarbers] = useState<Barber[]>([]);
  const [availableSlots, setAvailableSlots] = useState<TimeSlot[]>([]);

  // Selection State
  const [selectedBarber, setSelectedBarber] = useState<Barber | null>(null);
  const [selectedDate, setSelectedDate] = useState<string>("");
  const [selectedSlot, setSelectedSlot] = useState<TimeSlot | null>(null);

  // UI State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({ name: '', phone: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Initialize Data
  useEffect(() => {
    setBarbers(backendService.getBarbers());
    // Default to today's date
    const today = new Date().toISOString().split('T')[0];
    setSelectedDate(today);
  }, []);

  // Update slots when Barber or Date changes
  useEffect(() => {
    if (selectedBarber && selectedDate) {
      const slots = backendService.getAvailableSlots(selectedBarber.id, selectedDate);
      setAvailableSlots(slots);
      setSelectedSlot(null); // Reset slot selection
    } else {
      setAvailableSlots([]);
    }
  }, [selectedBarber, selectedDate]);

  const handleOpenModal = () => {
    if (selectedBarber && selectedSlot && selectedDate) {
      setIsModalOpen(true);
    }
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setFormData({ name: '', phone: '' });
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleConfirmBooking = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBarber || !selectedSlot || !selectedDate) return;

    setIsSubmitting(true);

    try {
      // 1. Save to internal "Backend"
      backendService.createAppointment({
        barberId: selectedBarber.id,
        barberName: selectedBarber.name,
        clientName: formData.name,
        clientPhone: formData.phone,
        date: selectedDate,
        time: selectedSlot.time
      });

      // 2. Refresh slots to show it's taken (if user stays on page)
      const slots = backendService.getAvailableSlots(selectedBarber.id, selectedDate);
      setAvailableSlots(slots);

      // 3. Create WhatsApp Link
      const businessPhone = "5511999999999"; 
      // Format date for display
      const dateDisplay = new Date(selectedDate).toLocaleDateString('pt-BR');
      const message = `Olá! Me chamo *${formData.name}*. Acabei de agendar no site com *${selectedBarber.name}* para dia *${dateDisplay}* às *${selectedSlot.time}*.`;
      const whatsappUrl = `https://wa.me/${businessPhone}?text=${encodeURIComponent(message)}`;

      setTimeout(() => {
        window.open(whatsappUrl, '_blank');
        setIsSubmitting(false);
        setIsModalOpen(false);

        // Reset major selections to prevent double booking easily
        setSelectedSlot(null);
        alert("Agendamento confirmado com sucesso!");
      }, 800);

    } catch (error: any) {
      alert(error.message);
      setIsSubmitting(false);
    }
  };

  return (
    <div id="agendamento" className="py-24 px-6 bg-[#0a0c10]">
      <div className="max-w-5xl mx-auto">
        <div className="text-center mb-16">
          <h2 className="text-5xl md:text-6xl font-display font-thin uppercase tracking-tight text-white mb-4">Agende seu Horário</h2>
          <p className="text-slate-400 text-lg font-sans font-light">Escolha seu profissional preferido e garanta seu slot.</p>
        </div>

        <div className="grid md:grid-cols-12 gap-8">

          {/* LEFT COL: Barber Selection */}
          <div className="md:col-span-5 bg-[#1c1c1e] rounded-[32px] p-8 border border-white/5">
            <h3 className="text-xl font-bold font-sans uppercase tracking-wider text-white mb-8 flex items-center gap-3">
              <span className="w-8 h-8 rounded-full bg-lime-400 text-black flex items-center justify-center font-bold text-sm">1</span>
              Escolha o Profissional
            </h3>
            <div className="space-y-4">
              {barbers.length === 0 ? (
                 <p className="text-slate-500 text-sm font-sans">Nenhum profissional cadastrado.</p>
              ) : (
                barbers.map((barber) => (
                  <div 
                    key={barber.id}
                    onClick={() => setSelectedBarber(barber)}
                    className={`group flex items-center gap-5 p-4 rounded-2xl cursor-pointer transition-all border ${
                      selectedBarber?.id === barber.id 
                        ? 'bg-lime-400 border-lime-400 shadow-lg shadow-lime-400/10' 
                        : 'bg-[#2c2c2e] border-transparent hover:bg-[#3a3a3c]'
                    }`}
                  >
                    <img src={barber.avatar} alt={barber.name} className="w-14 h-14 rounded-full object-cover border-2 border-transparent group-hover:border-white/20" />
                    <div>
                      <p className={`font-bold text-lg font-sans uppercase ${selectedBarber?.id === barber.id ? 'text-black' : 'text-white'}`}>
                        {barber.name}
                      </p>
                      <p className={`text-sm font-sans ${selectedBarber?.id === barber.id ? 'text-black/70' : 'text-slate-400'}`}>{barber.specialty}</p>
                    </div>
                    {selectedBarber?.id === barber.id && (
                      <Check className="w-6 h-6 text-black ml-auto" />
                    )}
                  </div>
                ))
              )}
            </div>
          </div>

          {/* RIGHT COL: Date & Time */}
          <div className="md:col-span-7 flex flex-col gap-6">

            {/* Date Picker */}
            <div className="bg-[#1c1c1e] rounded-[32px] p-8 border border-white/5">
               <h3 className="text-xl font-bold font-sans uppercase tracking-wider text-white mb-6 flex items-center gap-3">
                  <span className="w-8 h-8 rounded-full bg-[#2c2c2e] text-white flex items-center justify-center font-bold text-sm">2</span>
                  Data
               </h3>
               <div className="relative">
                 <input 
                    type="date" 
                    value={selectedDate}
                    min={new Date().toISOString().split('T')[0]}
                    onChange={(e) => setSelectedDate(e.target.value)}
                    className="w-full bg-[#2c2c2e] border-0 rounded-2xl p-4 text-white focus:ring-2 focus:ring-lime-400 text-lg uppercase font-bold tracking-wider cursor-pointer font-sans"
                 />
                 <CalendarIcon className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
               </div>
            </div>

            {/* Slots Grid */}
            <div className="bg-[#1c1c1e] rounded-[32px] p-8 border border-white/5 flex flex-col flex-grow">
              <h3 className="text-xl font-bold font-sans uppercase tracking-wider text-white mb-6 flex items-center gap-3">
                <span className="w-8 h-8 rounded-full bg-[#2c2c2e] text-white flex items-center justify-center font-bold text-sm">3</span>
                Horários Disponíveis
              </h3>

              {!selectedBarber ? (
                <div className="flex-grow flex items-center justify-center text-slate-500 text-sm py-8 bg-[#2c2c2e]/50 rounded-2xl border border-dashed border-slate-700 font-sans">
                   Selecione um barbeiro primeiro para ver a agenda.
                </div>
              ) : (
                <div className="grid grid-cols-3 sm:grid-cols-4 gap-3">
                  {availableSlots.map((slot, idx) => (
                    <button
                      key={idx}
                      disabled={!slot.available}
                      onClick={() => setSelectedSlot(slot)}
                      className={`
                        py-3 px-2 rounded-xl text-sm font-bold transition-all relative overflow-hidden font-sans
                        ${!slot.available 
                          ? 'bg-[#2c2c2e] text-slate-600 cursor-not-allowed opacity-50' 
                          : selectedSlot === slot
                            ? 'bg-lime-400 text-black shadow-lg shadow-lime-400/20 scale-105'
                            : 'bg-[#2c2c2e] text-white hover:bg-[#3a3a3c] hover:scale-105'
                        }
                      `}
                    >
                      {slot.time}
                      {!slot.available && <div className="absolute inset-0 flex items-center justify-center bg-black/10"><div className="w-full h-px bg-slate-500 rotate-45"></div></div>}
                    </button>
                  ))}
                  {availableSlots.length === 0 && (
                     <div className="col-span-full text-center text-slate-500 text-sm py-4 font-sans">
                        Nenhum horário disponível.
                     </div>
                  )}
                </div>
              )}

              <div className="mt-8 pt-8 border-t border-white/5">
                <button 
                  disabled={!selectedBarber || !selectedSlot || !selectedDate}
                  onClick={handleOpenModal}
                  className={`
                    w-full py-5 rounded-full font-normal text-xl flex items-center justify-center gap-3 font-economica uppercase tracking-wide
                    ${(!selectedBarber || !selectedSlot || !selectedDate)
                      ? 'bg-[#2c2c2e] text-slate-500 cursor-not-allowed'
                      : 'bg-white text-black hover:bg-lime-400 hover:text-black shadow-xl'
                    } transition-all duration-300
                  `}
                >
                  Confirmar Agendamento <ChevronRight className="w-5 h-5" />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Booking Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/90 backdrop-blur-xl animate-fade-in">
          <div className="bg-[#1c1c1e] border border-white/10 rounded-[32px] w-full max-w-md shadow-2xl relative overflow-hidden">

             {/* Header */}
             <div className="bg-[#2c2c2e] p-8 flex justify-between items-center">
                <h3 className="text-3xl font-display font-thin uppercase text-white">Finalizar</h3>
                <button onClick={handleCloseModal} className="text-slate-400 hover:text-white bg-black/20 p-2 rounded-full">
                  <X className="w-5 h-5" />
                </button>
             </div>

             {/* Body */}
             <form onSubmit={handleConfirmBooking} className="p-8 space-y-6">

                {/* Summary Card */}
                <div className="bg-lime-400 rounded-2xl p-6 flex items-center gap-5 mb-4 shadow-lg shadow-lime-400/10">
                   <div className="bg-black/10 p-3 rounded-full">
                      <CalendarIcon className="w-6 h-6 text-black" />
                   </div>
                   <div>
                      <p className="text-black/60 text-xs uppercase font-bold tracking-wider font-sans">Seu Horário</p>
                      <p className="text-black font-black text-xl font-sans">{selectedSlot?.time}</p>
                      <p className="text-black/80 font-medium text-sm font-sans">
                        {new Date(selectedDate).toLocaleDateString('pt-BR')} • {selectedBarber?.name}
                      </p>
                   </div>
                </div>

                <div className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 font-sans">Seu Nome</label>
                    <input 
                      type="text" 
                      name="name"
                      required
                      value={formData.name}
                      onChange={handleInputChange}
                      placeholder="Ex: João Silva"
                      className="w-full bg-[#0f1115] border border-[#2c2c2e] rounded-xl py-4 px-5 text-white placeholder-slate-600 focus:outline-none focus:border-lime-400 focus:ring-1 focus:ring-lime-400 transition-all font-medium font-sans"
                    />
                  </div>

                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 font-sans">WhatsApp</label>
                    <input 
                      type="tel" 
                      name="phone"
                      required
                      value={formData.phone}
                      onChange={handleInputChange}
                      placeholder="(11) 99999-9999"
                      className="w-full bg-[#0f1115] border border-[#2c2c2e] rounded-xl py-4 px-5 text-white placeholder-slate-600 focus:outline-none focus:border-lime-400 focus:ring-1 focus:ring-lime-400 transition-all font-medium font-sans"
                    />
                  </div>
                </div>

                <div className="pt-4">
                  <button 
                    type="submit" 
                    disabled={isSubmitting}
                    className="w-full bg-white hover:bg-lime-400 text-black font-normal text-xl py-4 rounded-full flex items-center justify-center gap-3 transition-all shadow-xl disabled:opacity-70 disabled:cursor-not-allowed font-economica uppercase tracking-wide"
                  >
                    {isSubmitting ? (
                      <>
                        <Loader2 className="w-5 h-5 animate-spin" />
                        Processando...
                      </>
                    ) : (
                      'Confirmar via WhatsApp'
                    )}
                  </button>
                  <p className="text-center text-[10px] text-slate-500 mt-4 uppercase tracking-widest font-sans">
                    Reserva segura • Confirmação instantânea
                  </p>
                </div>
             </form>

          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { backendService } from '../services/backendService';
import { Barber, Appointment } from '../types';
import { Plus, Trash2, Calendar, User, Phone, Search, Settings, Key, Save, Eye, EyeOff, Clock, X, Lock, Unlock, CheckCircle } from 'lucide-react';

export const AdminDashboard: React.FC = () => {
  const [barbers, setBarbers] = useState<Barber[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [activeTab, setActiveTab] = useState<'agenda' | 'equipe' | 'config'>('agenda');

  // Add Barber Form
  const [newBarberName, setNewBarberName] = useState('');
  const [newBarberSpecialty, setNewBarberSpecialty] = useState('');

  // Schedule Management State
  const [managingScheduleBarber, setManagingScheduleBarber] = useState<Barber | null>(null);
  const [scheduleDate, setScheduleDate] = useState(new Date().toISOString().split('T')[0]);
  const [scheduleSlots, setScheduleSlots] = useState<any[]>([]);

  // Config State
  const [apiKey, setApiKey] = useState('');
  const [showKey, setShowKey] = useState(false);

  useEffect(() => {
    refreshData();
    // Load API Key
    const storedKey = localStorage.getItem('BARBERFLOW_API_KEY');
    if (storedKey) setApiKey(storedKey);
  }, []);

  // Update schedule slots when date or barber changes
  useEffect(() => {
    if (managingScheduleBarber) {
      const slots = backendService.getAdminSlotsStatus(managingScheduleBarber.id, scheduleDate);
      setScheduleSlots(slots);
    }
  }, [managingScheduleBarber, scheduleDate, appointments]); // Re-fetch if appointments change

  const refreshData = () => {
    setBarbers(backendService.getBarbers());
    // Sort appointments by date/time desc
    const apps = backendService.getAppointments().sort((a, b) => {
      return new Date(`${b.date}T${b.time}`).getTime() - new Date(`${a.date}T${a.time}`).getTime();
    });
    setAppointments(apps);
  };

  const handleAddBarber = (e: React.FormEvent) => {
    e.preventDefault();
    if (newBarberName && newBarberSpecialty) {
      backendService.addBarber(newBarberName, newBarberSpecialty);
      setNewBarberName('');
      setNewBarberSpecialty('');
      refreshData();
    }
  };

  const handleDeleteBarber = (id: string) => {
    if (confirm('Tem certeza que deseja remover este barbeiro?')) {
      backendService.deleteBarber(id);
      refreshData();
    }
  };

  const handleSaveKey = (e: React.FormEvent) => {
    e.preventDefault();
    localStorage.setItem('BARBERFLOW_API_KEY', apiKey);
    alert('API Key salva com sucesso! O sistema agora usará esta chave para o Visagismo.');
  };

  const handleRemoveKey = () => {
    localStorage.removeItem('BARBERFLOW_API_KEY');
    setApiKey('');
    alert('API Key removida. O sistema tentará usar a variável de ambiente ou entrará em modo Demo.');
  };

  const toggleSlotBlock = (time: string, currentStatus: string) => {
    if (currentStatus === 'booked') {
      alert("Não é possível bloquear um horário que já possui agendamento. Cancele o agendamento primeiro.");
      return;
    }

    if (managingScheduleBarber) {
      backendService.toggleSlotBlock(managingScheduleBarber.id, scheduleDate, time);
      // Refresh local slots view
      const updatedSlots = backendService.getAdminSlotsStatus(managingScheduleBarber.id, scheduleDate);
      setScheduleSlots(updatedSlots);
    }
  };

  return (
    <div className="min-h-screen bg-[#0f1115] pt-24 pb-12 px-6">
      <div className="max-w-6xl mx-auto">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
          <h1 className="text-5xl font-display font-thin uppercase tracking-tight text-white">Painel Administrativo</h1>
          <div className="bg-[#1c1c1e] p-1 rounded-full border border-white/5 flex overflow-x-auto max-w-full">
             <button 
               onClick={() => setActiveTab('agenda')}
               className={`px-6 py-2 rounded-full font-bold text-sm transition-all whitespace-nowrap font-sans uppercase tracking-wide ${activeTab === 'agenda' ? 'bg-lime-400 text-black shadow-lg' : 'text-slate-400 hover:text-white'}`}
             >
               Agenda
             </button>
             <button 
               onClick={() => setActiveTab('equipe')}
               className={`px-6 py-2 rounded-full font-bold text-sm transition-all whitespace-nowrap font-sans uppercase tracking-wide ${activeTab === 'equipe' ? 'bg-lime-400 text-black shadow-lg' : 'text-slate-400 hover:text-white'}`}
             >
               Equipe
             </button>
             <button 
               onClick={() => setActiveTab('config')}
               className={`px-6 py-2 rounded-full font-bold text-sm transition-all whitespace-nowrap font-sans uppercase tracking-wide flex items-center gap-2 ${activeTab === 'config' ? 'bg-lime-400 text-black shadow-lg' : 'text-slate-400 hover:text-white'}`}
             >
               <Settings className="w-4 h-4" />
               Config
             </button>
          </div>
        </div>

        {activeTab === 'agenda' && (
          <div className="bg-[#1c1c1e] rounded-[32px] border border-white/5 p-8 shadow-2xl animate-fade-in">
            <h2 className="text-xl font-bold text-white mb-8 flex items-center gap-3 font-sans uppercase tracking-wider">
              <div className="bg-lime-400 p-2 rounded-lg text-black">
                 <Calendar className="w-5 h-5" />
              </div>
              Agendamentos Realizados
            </h2>

            {appointments.length === 0 ? (
              <div className="text-center py-20 border-2 border-dashed border-[#2c2c2e] rounded-2xl">
                <p className="text-slate-500 font-medium font-sans">Nenhum agendamento encontrado.</p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="border-b border-white/5 text-slate-500 text-xs uppercase tracking-widest font-bold font-sans">
                      <th className="pb-4 pl-4">Data/Hora</th>
                      <th className="pb-4">Cliente</th>
                      <th className="pb-4">Contato</th>
                      <th className="pb-4">Barbeiro</th>
                      <th className="pb-4 text-right pr-4">Status</th>
                    </tr>
                  </thead>
                  <tbody className="text-slate-200 text-sm font-sans">
                    {appointments.map((app) => (
                      <tr key={app.id} className="border-b border-white/5 hover:bg-[#2c2c2e] transition-colors group">
                        <td className="py-5 pl-4 font-mono font-medium">
                          <span className="text-lime-400">{new Date(app.date).toLocaleDateString('pt-BR')}</span> 
                          <span className="text-slate-600 mx-2">|</span> 
                          {app.time}
                        </td>
                        <td className="py-5 font-bold text-white">{app.clientName}</td>
                        <td className="py-5 text-slate-400">
                           {app.clientPhone}
                        </td>
                        <td className="py-5">
                          <span className="bg-[#0f1115] px-3 py-1 rounded-full border border-white/10 text-xs font-medium uppercase">
                            {app.barberName}
                          </span>
                        </td>
                        <td className="py-5 text-right pr-4">
                          <span className="text-lime-400 bg-lime-400/10 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider">
                            CONFIRMADO
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {activeTab === 'equipe' && (
          <div className="grid md:grid-cols-3 gap-8 animate-fade-in">
            {/* List */}
            <div className="md:col-span-2 grid gap-4">
              {barbers.map((barber) => (
                <div key={barber.id} className="bg-[#1c1c1e] p-5 rounded-[24px] border border-white/5 flex items-center justify-between group hover:border-lime-400/30 transition-all">
                  <div className="flex items-center gap-5">
                    <img src={barber.avatar} alt={barber.name} className="w-14 h-14 rounded-full object-cover border-2 border-[#2c2c2e]" />
                    <div>
                      <h3 className="font-bold text-lg text-white group-hover:text-lime-400 transition-colors font-sans uppercase">{barber.name}</h3>
                      <p className="text-sm text-slate-400 font-medium font-sans">{barber.specialty}</p>
                    </div>
                  </div>

                  <div className="flex gap-2">
                    <button 
                      onClick={() => setManagingScheduleBarber(barber)}
                      className="p-3 text-slate-400 hover:text-white hover:bg-white/10 rounded-xl transition-colors tooltip relative group/btn"
                      title="Gerenciar Horários"
                    >
                      <Clock className="w-5 h-5" />
                    </button>
                    <button 
                      onClick={() => handleDeleteBarber(barber.id)}
                      className="p-3 text-red-400 hover:bg-red-500/10 rounded-xl transition-colors"
                      title="Remover Profissional"
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                </div>
              ))}
            </div>

            {/* Add Form */}
            <div className="bg-[#1c1c1e] p-8 rounded-[32px] border border-white/5 h-fit shadow-xl">
              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-3 font-sans uppercase tracking-wider">
                <div className="bg-lime-400 p-2 rounded-lg text-black">
                   <Plus className="w-4 h-4" />
                </div>
                Novo Profissional
              </h3>
              <form onSubmit={handleAddBarber} className="space-y-5">
                <div>
                  <label className="text-xs text-slate-500 font-bold uppercase tracking-widest block mb-2 font-sans">Nome Completo</label>
                  <input 
                    type="text" 
                    value={newBarberName}
                    onChange={(e) => setNewBarberName(e.target.value)}
                    className="w-full bg-[#0f1115] border border-[#2c2c2e] rounded-xl p-3 text-white focus:border-lime-400 focus:outline-none focus:ring-1 focus:ring-lime-400 font-medium font-sans"
                    placeholder="Ex: Pedro Santos"
                  />
                </div>
                <div>
                  <label className="text-xs text-slate-500 font-bold uppercase tracking-widest block mb-2 font-sans">Especialidade</label>
                  <input 
                    type="text" 
                    value={newBarberSpecialty}
                    onChange={(e) => setNewBarberSpecialty(e.target.value)}
                    className="w-full bg-[#0f1115] border border-[#2c2c2e] rounded-xl p-3 text-white focus:border-lime-400 focus:outline-none focus:ring-1 focus:ring-lime-400 font-medium font-sans"
                    placeholder="Ex: Barba & Freestyle"
                  />
                </div>
                <button 
                  type="submit"
                  className="w-full bg-white hover:bg-lime-400 text-black font-normal text-xl py-4 rounded-full transition-all shadow-lg mt-2 font-economica uppercase tracking-wide"
                >
                  Cadastrar
                </button>
              </form>
            </div>
          </div>
        )}

        {activeTab === 'config' && (
          <div className="max-w-2xl mx-auto animate-fade-in">
             <div className="bg-[#1c1c1e] rounded-[32px] border border-white/5 p-8 shadow-2xl">
                <h2 className="text-xl font-bold text-white mb-2 flex items-center gap-3 font-sans uppercase tracking-wider">
                  <div className="bg-lime-400 p-2 rounded-lg text-black">
                    <Key className="w-5 h-5" />
                  </div>
                  Configuração de IA
                </h2>
                <p className="text-slate-400 text-sm mb-8 font-sans">
                  Insira sua Google Gemini API Key para habilitar os recursos de Visagismo e Geração de Imagem. 
                  A chave será salva localmente no seu navegador.
                </p>

                <form onSubmit={handleSaveKey} className="space-y-6">
                  <div>
                    <label className="text-xs text-slate-500 font-bold uppercase tracking-widest block mb-2 font-sans">Gemini API Key</label>
                    <div className="relative">
                      <input 
                        type={showKey ? "text" : "password"}
                        value={apiKey}
                        onChange={(e) => setApiKey(e.target.value)}
                        className="w-full bg-[#0f1115] border border-[#2c2c2e] rounded-xl p-4 pr-12 text-white focus:border-lime-400 focus:outline-none focus:ring-1 focus:ring-lime-400 font-mono text-sm"
                        placeholder="AIzaSy..."
                      />
                      <button 
                        type="button"
                        onClick={() => setShowKey(!showKey)}
                        className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white"
                      >
                        {showKey ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                      </button>
                    </div>
                  </div>

                  <div className="flex gap-4">
                    <button 
                      type="submit"
                      className="flex-1 bg-lime-400 hover:bg-lime-300 text-black font-normal text-lg py-4 rounded-full transition-all shadow-lg flex items-center justify-center gap-2 font-economica uppercase tracking-wide"
                    >
                      <Save className="w-4 h-4" />
                      Salvar Chave
                    </button>

                    {apiKey && (
                      <button 
                        type="button"
                        onClick={handleRemoveKey}
                        className="px-8 py-4 rounded-full bg-[#2c2c2e] hover:bg-red-500/10 hover:text-red-400 text-slate-400 transition-all font-economica font-normal text-lg"
                      >
                        Remover
                      </button>
                    )}
                  </div>
                </form>

                <div className="mt-8 pt-8 border-t border-white/5">
                   <p className="text-xs text-slate-600 text-center font-sans">
                      Não tem uma chave? <a href="https://aistudio.google.com/app/apikey" target="_blank" className="text-lime-400 hover:underline">Gerar no Google AI Studio</a>.
                   </p>
                </div>
             </div>
          </div>
        )}
      </div>

      {/* SCHEDULE MANAGEMENT MODAL */}
      {managingScheduleBarber && (
        <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-xl flex items-center justify-center p-6 animate-fade-in">
           <div className="bg-[#1c1c1e] w-full max-w-2xl rounded-[32px] border border-white/10 shadow-2xl relative overflow-hidden flex flex-col max-h-[90vh]">

              {/* Modal Header */}
              <div className="bg-[#2c2c2e] p-6 flex items-center justify-between flex-shrink-0">
                 <div className="flex items-center gap-4">
                    <img src={managingScheduleBarber.avatar} className="w-12 h-12 rounded-full border-2 border-lime-400" />
                    <div>
                       <h3 className="text-white font-bold text-lg font-sans uppercase">{managingScheduleBarber.name}</h3>
                       <p className="text-slate-400 text-xs font-sans">Gerenciar Disponibilidade</p>
                    </div>
                 </div>
                 <button 
                   onClick={() => setManagingScheduleBarber(null)}
                   className="p-2 hover:bg-white/10 rounded-full text-slate-400 hover:text-white transition-colors"
                 >
                    <X className="w-6 h-6" />
                 </button>
              </div>

              {/* Modal Content */}
              <div className="p-8 overflow-y-auto">

                 {/* Date Selector */}
                 <div className="mb-8">
                    <label className="text-xs text-slate-500 font-bold uppercase tracking-widest block mb-2 font-sans">Selecione a Data</label>
                    <div className="relative">
                      <input 
                        type="date" 
                        value={scheduleDate}
                        onChange={(e) => setScheduleDate(e.target.value)}
                        className="w-full bg-[#0f1115] border border-[#2c2c2e] rounded-xl p-4 text-white font-bold text-lg focus:border-lime-400 focus:outline-none uppercase font-sans"
                      />
                      <Calendar className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" />
                    </div>
