        : fullText.substring(0, text.length + 1)
      );

      let speed = isDeleting ? 30 : 100; // Deletar é mais rápido que digitar

      if (!isDeleting && text === fullText) {
        speed = 2000; // Pausa ao terminar a frase
        setIsDeleting(true);
      } else if (isDeleting && text === '') {
        setIsDeleting(false);
        setLoopNum(loopNum + 1);
        speed = 500; // Pausa antes de começar a próxima
      }

      setTypingSpeed(speed);
    };

    const timer = setTimeout(handleType, typingSpeed);

    return () => clearTimeout(timer);
  }, [text, isDeleting, loopNum, phrases, typingSpeed]);

  return (
    <section className="relative py-24 px-6 text-center overflow-hidden">
      {/* Background Abstract Shapes */}
      <div className="absolute top-20 left-10 w-64 h-64 bg-lime-400/5 rounded-full blur-[80px] pointer-events-none"></div>
      <div className="absolute bottom-10 right-10 w-96 h-96 bg-blue-500/5 rounded-full blur-[100px] pointer-events-none"></div>

      <div className="relative z-10 max-w-5xl mx-auto flex flex-col items-center">

        <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 border border-white/10 mb-8 animate-fade-in">
           <span className="w-2 h-2 rounded-full bg-lime-400 animate-pulse"></span>
           <span className="text-lg font-medium text-slate-300 tracking-widest uppercase font-display">Nova IA 2.0 Disponível</span>
        </div>

        <h2 className="text-7xl md:text-9xl font-display font-medium text-white mb-8 leading-[0.9] tracking-tighter uppercase min-h-[300px] md:min-h-[auto]">
          O corte perfeito <br />
          <span className="relative inline-block">
            <span className="relative z-10 text-transparent bg-clip-text bg-gradient-to-r from-lime-300 to-lime-500 font-medium">
              {text}
            </span>
            <span className="inline-block w-1.5 h-[0.75em] align-middle bg-lime-400 ml-2 animate-pulse mb-2 md:mb-4"></span>
          </span>
          <br /> desenhado para você.
        </h2>

        <p className="text-3xl md:text-4xl text-slate-400 mb-12 max-w-4xl mx-auto leading-relaxed font-sans font-thin">
          Pare de adivinhar. Nossa IA analisa 50+ pontos do seu rosto para recomendar o estilo exato que maximiza sua estética.
        </p>

        <div className="flex flex-col sm:flex-row gap-5 w-full justify-center">
          <button 
            onClick={onStartVisagism}
            className="group relative flex items-center justify-center gap-3 bg-lime-400 hover:bg-lime-300 text-slate-900 font-normal font-economica text-3xl py-5 px-12 rounded-full transition-all transform hover:scale-105 shadow-[0_0_40px_rgba(163,230,53,0.3)] tracking-wide uppercase"
          >
            <Sparkles className="w-6 h-6 fill-slate-900 group-hover:rotate-12 transition-transform" />
            Análise de Visagismo
          </button>

          <button 
            onClick={onStartScheduling}
            className="flex items-center justify-center gap-3 bg-[#1c1c1e] hover:bg-[#2c2c2e] text-white font-normal font-economica text-3xl py-5 px-12 rounded-full border border-white/5 transition-all hover:border-white/20 tracking-wide uppercase"
          >
            <Calendar className="w-6 h-6" />
            Agendar Agora
          </button>
        </div>

        {/* Social Proof / Tech Badge */}
        <div className="mt-16 flex items-center justify-center gap-8 opacity-40 grayscale hover:grayscale-0 transition-all duration-500 font-sans">
           <div className="flex items-center gap-2">
             <div className="text-lg font-medium font-mono border border-white/30 rounded px-2 py-1">GEMINI</div>
             <span className="text-xl font-thin">Powered Engine</span>
           </div>
           <div className="h-4 w-px bg-white/20"></div>
