              <span className="w-8 h-8 rounded-full bg-lime-400 text-black flex items-center justify-center font-bold text-lg">1</span>
              Escolha o Profissional
            </h3>
            <div className="space-y-4">
              {barbers.length === 0 ? (
                 <p className="text-slate-500 text-lg font-sans font-thin">Nenhum profissional cadastrado.</p>
              ) : (
                barbers.map((barber) => (
                  <div 
                    key={barber.id}
                    onClick={() => setSelectedBarber(barber)}
                    className={`group flex items-center gap-5 p-4 rounded-2xl cursor-pointer transition-all border ${
