                    w-full py-5 rounded-full font-normal text-3xl flex items-center justify-center gap-3 font-economica uppercase tracking-wide
                    ${(!selectedBarber || !selectedSlot || !selectedDate)
                      ? 'bg-[#2c2c2e] text-slate-500 cursor-not-allowed'
                      : 'bg-white text-black hover:bg-lime-400 hover:text-black shadow-xl'
                    } transition-all duration-300
                  `}
                >
                  Confirmar Agendamento <ChevronRight className="w-6 h-6" />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Booking Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/90 backdrop-blur-xl animate-fade-in">
          <div className="bg-[#1c1c1e] border border-white/10 rounded-[32px] w-full max-w-md shadow-2xl relative overflow-hidden">

             {/* Header */}
             <div className="bg-[#2c2c2e] p-8 flex justify-between items-center">
                <h3 className="text-4xl font-display font-medium uppercase text-white">Finalizar</h3>
                <button onClick={handleCloseModal} className="text-slate-400 hover:text-white bg-black/20 p-2 rounded-full">
                  <X className="w-5 h-5" />
                </button>
             </div>

             {/* Body */}
             <form onSubmit={handleConfirmBooking} className="p-8 space-y-6">

                {/* Summary Card */}
                <div className="bg-lime-400 rounded-2xl p-6 flex items-center gap-5 mb-4 shadow-lg shadow-lime-400/10">
                   <div className="bg-black/10 p-3 rounded-full">
                      <CalendarIcon className="w-6 h-6 text-black" />
                   </div>
                   <div>
                      <p className="text-black/60 text-sm uppercase font-bold tracking-wider font-sans">Seu Horário</p>
                      <p className="text-black font-medium text-3xl font-sans">{selectedSlot?.time}</p>
                      <p className="text-black/80 font-medium text-lg font-sans">
                        {new Date(selectedDate).toLocaleDateString('pt-BR')} • {selectedBarber?.name}
                      </p>
                   </div>
                </div>

                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-bold text-slate-400 uppercase tracking-widest mb-2 font-sans">Seu Nome</label>
                    <input 
                      type="text" 
                      name="name"
                      required
                      value={formData.name}
                      onChange={handleInputChange}
                      placeholder="Ex: João Silva"
                      className="w-full bg-[#0f1115] border border-[#2c2c2e] rounded-xl py-4 px-5 text-white placeholder-slate-600 focus:outline-none focus:border-lime-400 focus:ring-1 focus:ring-lime-400 transition-all font-medium text-xl font-sans"
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-bold text-slate-400 uppercase tracking-widest mb-2 font-sans">WhatsApp</label>
                    <input 
                      type="tel" 
                      name="phone"
                      required
                      value={formData.phone}
                      onChange={handleInputChange}
                      placeholder="(11) 99999-9999"
                      className="w-full bg-[#0f1115] border border-[#2c2c2e] rounded-xl py-4 px-5 text-white placeholder-slate-600 focus:outline-none focus:border-lime-400 focus:ring-1 focus:ring-lime-400 transition-all font-medium text-xl font-sans"
                    />
                  </div>
                </div>

                <div className="pt-4">
                  <button 
                    type="submit" 
                    disabled={isSubmitting}
                    className="w-full bg-white hover:bg-lime-400 text-black font-normal text-2xl py-4 rounded-full flex items-center justify-center gap-3 transition-all shadow-xl disabled:opacity-70 disabled:cursor-not-allowed font-economica uppercase tracking-wide"
                  >
                    {isSubmitting ? (
                      <>
                        <Loader2 className="w-5 h-5 animate-spin" />
                        Processando...
                      </>
                    ) : (
                      'Confirmar via WhatsApp'
                    )}
                  </button>
                  <p className="text-center text-xs text-slate-500 mt-4 uppercase tracking-widest font-sans font-medium">
                    Reserva segura • Confirmação instantânea
                  </p>
                </div>
             </form>

          </div>
        </div>
      )}
    </div>
  );
};

