import React, { useState, useRef, useEffect } from 'react';
import { Camera, AlertCircle, Loader2, User, RefreshCw, ImageIcon, Filter, Layers, ScanFace, Check, Cpu, Zap, Maximize2, X, Terminal, ShieldCheck } from 'lucide-react';
import { analyzeHairstyle, generateHairstylePreview } from '../services/geminiService';
import { VisagismAnalysisResult } from '../types';
import { STYLE_PREFERENCES } from '../constants';

const LOADING_STEPS = [
  "Inicializando rede neural...",
  "Detectando pontos de referência facial...",
  "Mapeando estrutura óssea (Mandíbula/Zigomático)...",
  "Calculando proporções áureas...",
  "Consultando base de dados de visagismo...",
  "Gerando recomendações personalizadas..."
];

export const VisagismFeature: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);

  // Loading State Expanded
  const [loading, setLoading] = useState(false);
  const [loadingStepIndex, setLoadingStepIndex] = useState(0);
  const [loadingProgress, setLoadingProgress] = useState(0);

  const [result, setResult] = useState<VisagismAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState<string>("Todos");

  // State for image generation
  const [previewImages, setPreviewImages] = useState<Record<number, string>>({});
  const [loadingPreviews, setLoadingPreviews] = useState<Record<number, boolean>>({});
  const [showOriginal, setShowOriginal] = useState<Record<number, boolean>>({});

  const [fullscreenIndex, setFullscreenIndex] = useState<number | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Enhanced Loading Effect
  useEffect(() => {
    let stepInterval: any;
    let progressInterval: any;

    if (loading) {
      setLoadingStepIndex(0);
      setLoadingProgress(0);

      const totalSteps = LOADING_STEPS.length;
      // Total estimated time roughly 6-7 seconds
      const stepDuration = 1200; 

      // Step incrementer
      stepInterval = setInterval(() => {
        setLoadingStepIndex((prev) => {
          if (prev < totalSteps - 1) return prev + 1;
          return prev;
        });
      }, stepDuration);

      // Smooth progress bar incrementer
      progressInterval = setInterval(() => {
        setLoadingProgress((prev) => {
          if (prev >= 99) return 99; // Wait for actual finish
          // Add a random small amount to simulate realistic processing variations
          return prev + (Math.random() * 1.5);
        });
      }, 100);
    }

    return () => {
      clearInterval(stepInterval);
      clearInterval(progressInterval);
    };
  }, [loading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      setError("A imagem deve ter no máximo 5MB.");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setImage(reader.result as string);
      setResult(null);
      setError(null);
      setPreviewImages({});
      setShowOriginal({});
      setFullscreenIndex(null);
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!image) return;

    setLoading(true);
    setError(null);

    try {
      const analysis = await analyzeHairstyle(image, selectedStyle);
      setLoadingProgress(100); // Force complete
      // Small delay to show 100%
      setTimeout(() => {
        setResult(analysis);
        setLoading(false);
      }, 600);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Erro ao analisar a imagem. Verifique a API Key ou tente novamente.");
      setLoading(false);
    }
  };

  const handleGeneratePreview = async (index: number, cutName: string) => {
    if (!image) return;

    setLoadingPreviews(prev => ({ ...prev, [index]: true }));

    try {
      const generatedImage = await generateHairstylePreview(image, cutName);
      setPreviewImages(prev => ({ ...prev, [index]: generatedImage }));
      setShowOriginal(prev => ({ ...prev, [index]: false }));
    } catch (err: any) {
      console.error("Failed to generate preview", err);
      // Show user-friendly alert since we don't have a global error state for previews
      alert(err.message || "Não foi possível gerar a simulação neste momento. (Erro de API/Cota)");
    } finally {
      setLoadingPreviews(prev => ({ ...prev, [index]: false }));
    }
  };

  const toggleBeforeAfter = (index: number) => {
    setShowOriginal(prev => ({ ...prev, [index]: !prev[index] }));
  };

  const handleReset = () => {
    setImage(null);
    setResult(null);
    setError(null);
    setPreviewImages({});
    setLoadingPreviews({});
    setShowOriginal({});
    setFullscreenIndex(null);
    setSelectedStyle("Todos");
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  return (
    <div id="visagismo" className="max-w-5xl mx-auto py-16 px-6">

      {/* --- ULTRA HUD LOADING OVERLAY --- */}
      {loading && (
        <div className="fixed inset-0 z-[100] bg-[#0f1115] flex flex-col items-center justify-center p-6 overflow-hidden">

          {/* Animated Matrix Grid Background */}
          <div className="absolute inset-0 opacity-20 pointer-events-none" 
               style={{ 
                 backgroundImage: 'radial-gradient(circle, #a3e635 1px, transparent 1px)', 
                 backgroundSize: '40px 40px',
                 animation: 'pulse 4s infinite'
               }}>
          </div>
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-lime-400 to-transparent opacity-50"></div>

          <div className="relative z-10 w-full max-w-3xl flex flex-col md:flex-row gap-12 items-center justify-center">

            {/* LEFT: Biometric Scanner Visual */}
            <div className="relative w-72 h-72 flex-shrink-0">
               {/* Rotating Rings - Lime Colored */}
               <div className="absolute inset-0 border border-lime-400/20 rounded-full animate-[spin_10s_linear_infinite]"></div>
               <div className="absolute inset-4 border border-lime-400/10 rounded-full animate-[spin_8s_linear_infinite_reverse]"></div>
               <div className="absolute inset-0 border-t-2 border-lime-400 rounded-full animate-[spin_2s_linear_infinite]"></div>

               {/* Face Wireframe Simulation (SVG) */}
               <div className="absolute inset-0 flex items-center justify-center p-10 opacity-80">
                  <svg viewBox="0 0 100 100" fill="none" stroke="currentColor" className="w-full h-full text-lime-400/60 stroke-1">
                    <path d="M20,30 Q50,5 80,30" /> {/* Forehead */}
                    <path d="M20,30 L20,60 Q20,90 50,95 Q80,90 80,60 L80,30" /> {/* Jaw */}
                    <path d="M35,45 Q50,45 65,45" /> {/* Eyes line */}
                    <path d="M48,50 L48,65" /> {/* Nose */}
                    <path d="M35,75 Q50,80 65,75" /> {/* Mouth */}

                    {/* Scanning Grid inside face */}
                    <path d="M20,40 L80,40" strokeOpacity="0.2" />
                    <path d="M20,50 L80,50" strokeOpacity="0.2" />
                    <path d="M25,60 L75,60" strokeOpacity="0.2" />
                    <path d="M30,70 L70,70" strokeOpacity="0.2" />
                    <path d="M40,20 L40,90" strokeOpacity="0.2" />
                    <path d="M60,20 L60,90" strokeOpacity="0.2" />
                  </svg>
               </div>

               {/* Laser Scan Effect */}
               <div className="absolute inset-0 bg-gradient-to-b from-transparent via-lime-400/30 to-transparent h-[15%] w-full animate-[scan_2s_linear_infinite]"></div>

               {/* Data Points */}
               <div className="absolute top-1/4 left-1/4 w-1.5 h-1.5 bg-lime-400 rounded-full animate-ping"></div>
               <div className="absolute bottom-1/3 right-1/3 w-1.5 h-1.5 bg-lime-400 rounded-full animate-ping delay-300"></div>
               <div className="absolute top-1/2 right-1/4 w-1.5 h-1.5 bg-lime-400 rounded-full animate-ping delay-700"></div>
            </div>

            {/* RIGHT: Data Terminal & Progress */}
            <div className="flex-grow w-full max-w-md">
                <div className="mb-8">
                   <h3 className="text-6xl font-display font-medium uppercase tracking-tighter mb-2 text-white">
                     Analisando<span className="animate-pulse text-lime-400">_</span>
                   </h3>
                   <div className="flex justify-between text-lg text-lime-400 font-sans font-medium uppercase tracking-widest mb-3">
                      <span>Gemini AI Core</span>
                      <span>Processing...</span>
                   </div>

                   {/* Progress Bar */}
                   <div className="h-4 w-full bg-[#1c1c1e] rounded-full overflow-hidden border border-white/5">
                      <div 
                        className="h-full bg-lime-400 shadow-[0_0_20px_#a3e635] transition-all duration-200 ease-out"
                        style={{ width: `${loadingProgress}%` }}
                      ></div>
                   </div>
                   <div className="text-right text-lime-400 font-mono font-medium mt-2 text-2xl">
                      {Math.floor(loadingProgress)}%
                   </div>
                </div>

                {/* Terminal Log */}
                <div className="bg-black/50 border border-white/10 rounded-2xl p-6 font-mono text-sm md:text-base backdrop-blur-md h-48 overflow-hidden relative">

                   <div className="flex flex-col gap-3 h-full justify-end pb-2">
                      {LOADING_STEPS.map((step, index) => {
                        const isDone = index < loadingStepIndex;
                        const isCurrent = index === loadingStepIndex;
                        const isPending = index > loadingStepIndex;

                        if (isPending) return null; 

                        return (
                          <div key={index} className={`flex items-start gap-3 animate-fade-in-left`}>
                              <span className="text-slate-600 shrink-0 font-medium">
                                {`0${index + 1}`}
                              </span>
                              <div className="flex-grow">
                                <span className={`${isCurrent ? 'text-lime-400 font-medium' : 'text-slate-400 font-extralight'}`}>
                                  {step}
                                </span>
                              </div>
                              {isDone && <Check className="w-4 h-4 text-lime-500 mt-0.5" />}
                          </div>
                        );
                      })}
                   </div>
                </div>
            </div>

          </div>
        </div>
      )}

      {/* --- IMAGE FULLSCREEN MODAL --- */}
      {fullscreenIndex !== null && result && (
        <div className="fixed inset-0 z-[200] bg-black/95 backdrop-blur-xl flex flex-col items-center justify-center p-4 animate-fade-in" onClick={() => setFullscreenIndex(null)}>
          <button
            onClick={() => setFullscreenIndex(null)}
            className="absolute top-6 right-6 text-white bg-white/10 hover:bg-white/20 p-4 rounded-full transition-all z-[210]"
          >
            <X className="w-6 h-6" />
          </button>

          <div 
            className="relative w-full max-w-6xl h-full max-h-[90vh] flex flex-col items-center justify-center"
            onClick={(e) => e.stopPropagation()}
          >
              {(() => {
                 const hasGenerated = !!previewImages[fullscreenIndex];
                 const isShowOriginal = showOriginal[fullscreenIndex];
                 const displayImage = (hasGenerated && !isShowOriginal) ? previewImages[fullscreenIndex] : image!;
                 const cut = result.suggestedCuts[fullscreenIndex];

                 return (
                   <>
                     <img
                       src={displayImage}
                       alt={cut.name}
                       className="w-auto h-auto max-w-full max-h-full object-contain rounded-2xl shadow-2xl border border-white/10"
                     />

                     <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-6 bg-[#1c1c1e] px-8 py-5 rounded-full border border-white/10 shadow-2xl">
                        <span className="text-white font-display font-medium uppercase tracking-wide text-3xl">{cut.name}</span>
                        <div className="h-6 w-px bg-white/20"></div>

                        {hasGenerated && (
                           <button
                              onClick={() => toggleBeforeAfter(fullscreenIndex)}
                              className="flex items-center gap-2 text-xl font-normal text-lime-400 hover:text-lime-300 transition-colors uppercase tracking-widest font-economica"
                           >
                              <Layers className="w-5 h-5" />
                              {isShowOriginal ? "Ver Simulação" : "Ver Original"}
                           </button>
                        )}
                        {!hasGenerated && (
                           <span className="text-slate-500 text-lg font-sans font-extralight">Simulação não gerada</span>
                        )}
                     </div>
                   </>
                 )
              })()}
          </div>
        </div>
      )}


      <div className="text-center mb-12">
        <h3 className="text-lime-400 font-medium uppercase tracking-widest text-lg mb-3 flex items-center justify-center gap-2 font-sans">
           <Zap className="w-4 h-4 fill-current" /> Feature Premium
        </h3>
        <h2 className="text-6xl md:text-8xl font-display font-medium uppercase tracking-tight text-white mb-4">
          Visagismo com IA
        </h2>
        <p className="text-slate-400 max-w-2xl mx-auto text-3xl font-sans font-extralight">
          Análise biométrica avançada para encontrar a geometria perfeita.
        </p>
      </div>

      {/* Upload Section */}
      {!result && (
        <div className="bg-[#1c1c1e] rounded-[32px] p-8 md:p-12 border border-white/5 relative overflow-hidden group hover:border-lime-400/30 transition-all duration-500">

          {!image ? (
            <div 
              className="border-2 border-dashed border-white/10 rounded-[24px] p-16 text-center cursor-pointer hover:border-lime-400 hover:bg-white/5 transition-all duration-300 relative group/upload"
              onClick={() => fileInputRef.current?.click()}
            >
              <div className="w-24 h-24 bg-[#0f1115] rounded-full flex items-center justify-center mx-auto mb-8 group-hover/upload:scale-110 group-hover/upload:bg-lime-400 transition-all duration-300">
                <Camera className="w-10 h-10 text-slate-400 group-hover/upload:text-black transition-colors" />
              </div>
              <h4 className="text-5xl font-display font-medium uppercase text-white mb-3">Tire uma selfie ou envie uma foto</h4>
              <p className="text-slate-500 mb-8 font-sans font-extralight text-2xl">Formatos suportados: JPG, PNG (Max 5MB)</p>
