                  <div className="flex items-center gap-2 mb-4 justify-center text-slate-400 uppercase tracking-widest text-lg font-medium font-sans">
                    <Filter className="w-4 h-4 text-lime-400" />
                    <span>Filtrar Estilo (Opcional)</span>
