                          px-5 py-2.5 rounded-full text-lg font-medium transition-all duration-300 font-sans
                          ${selectedStyle === style 
                            ? 'bg-lime-400 text-black shadow-lg shadow-lime-400/20 scale-105' 
                            : 'bg-[#2c2c2e] text-slate-300 hover:bg-[#3a3a3c] hover:text-white'
                          }
                        `}
                      >
                        {style}
                      </button>
                    ))}
                  </div>
              </div>

              {error && (
                <div className="bg-red-500/10 border border-red-500/20 text-red-400 px-6 py-4 rounded-xl flex items-center gap-3 mb-8 w-full max-w-md font-sans">
                  <AlertCircle className="w-5 h-5 flex-shrink-0" />
                  <p className="font-medium text-xl">{error}</p>
                </div>
              )}

              <button
                onClick={handleAnalyze}
                disabled={loading}
                className={`
                  w-full max-w-md py-5 px-8 rounded-full font-normal text-3xl flex items-center justify-center gap-4 shadow-xl font-economica uppercase tracking-wide
                  ${loading 
                    ? 'bg-[#2c2c2e] text-slate-500 cursor-not-allowed' 
                    : 'bg-lime-400 text-black hover:bg-lime-300 hover:scale-[1.02] hover:shadow-lime-400/20'
                  } transition-all duration-300
                `}
              >
                  <>
                    <Cpu className="w-6 h-6" />
                    INICIAR ANÁLISE
                  </>
              </button>
            </div>
          )}
        </div>
      )}

      {/* Results Section */}
      {result && (
        <div className="animate-fade-in space-y-8">

          {/* Main Result Card */}
          <div className="bg-[#1c1c1e] rounded-[32px] p-8 md:p-12 border border-white/5 flex flex-col md:flex-row gap-10 items-center md:items-start relative overflow-hidden">
             <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-lime-400/5 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2 pointer-events-none"></div>

            <div className="w-40 h-40 rounded-[32px] border-4 border-[#2c2c2e] flex items-center justify-center bg-[#0f1115] flex-shrink-0 shadow-2xl relative z-10">
               <img src={image!} alt="User" className="w-full h-full object-cover opacity-50 rounded-[28px]" />
               <div className="absolute inset-0 flex items-center justify-center">
                  <ScanFace className="w-12 h-12 text-lime-400" />
               </div>
            </div>

            <div className="text-center md:text-left relative z-10 flex-1">
              <div className="inline-flex items-center gap-2 bg-lime-400/10 px-3 py-1 rounded-full text-lime-400 text-lg font-medium uppercase tracking-wider mb-4 font-sans">
                 <ShieldCheck className="w-4 h-4" />
                 Análise Concluída
              </div>
              <h2 className="text-6xl md:text-7xl font-display font-medium uppercase text-white mb-4">
                Formato <span className="text-lime-400">{result.faceShape}</span>
              </h2>
              <div className="flex flex-col gap-4">
                 <p className="text-slate-400 text-2xl md:text-3xl leading-relaxed max-w-2xl font-sans font-extralight">
                  Para este formato, a IA selecionou estilos que harmonizam a geometria facial, 
                  valorizando seus pontos fortes.
                </p>
              </div>
            </div>

            <div className="md:ml-auto relative z-10 self-center md:self-start">
               <button 
                onClick={handleReset} 
                className="px-8 py-3 rounded-full bg-[#2c2c2e] hover:bg-[#3a3a3c] text-white text-2xl font-normal transition-all font-economica uppercase tracking-wide"
              >
                Nova Análise
              </button>
            </div>
          </div>

          {/* Cuts Grid */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {result.suggestedCuts.map((cut, index) => {
              const hasGenerated = !!previewImages[index];
              const isShowOriginal = showOriginal[index];
              const isLoadingThis = loadingPreviews[index];
              const displayImage = (hasGenerated && !isShowOriginal) ? previewImages[index] : image!;

              return (
              <div 
                key={index} 
                className="bg-[#1c1c1e] rounded-[32px] overflow-hidden hover:bg-[#252527] transition-all duration-300 group flex flex-col hover:shadow-2xl border border-transparent hover:border-white/5"
              >
                {/* Image Area */}
                <div className="relative w-full aspect-[4/5] bg-black flex items-center justify-center overflow-hidden">

                  {isLoadingThis ? (
                     <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-black/80 backdrop-blur-sm">
                       <Loader2 className="w-8 h-8 animate-spin text-lime-400 mb-2" />
                       <span className="text-sm font-medium text-lime-400 tracking-widest font-sans">GERANDO PREVIEW...</span>
                     </div>
                  ) : hasGenerated || isShowOriginal ? (
                     <>
                        <img 
                          src={displayImage} 
                          alt={`Visualização ${cut.name}`} 
                          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105 cursor-pointer"
                          onClick={() => setFullscreenIndex(index)}
                        />
                        {/* Toggle Badge */}
                        <div className="absolute top-4 left-4 z-10 pointer-events-none">
                           <span className={`text-xs font-black px-3 py-1.5 rounded-full backdrop-blur-md shadow-lg border font-sans uppercase ${isShowOriginal ? 'bg-black/60 text-white border-white/20' : 'bg-lime-400 text-black border-lime-400'}`}>
                              {isShowOriginal ? 'ORIGINAL' : 'IA PREVIEW'}
                           </span>
                        </div>
                     </>
                  ) : (
                    <div className="flex flex-col items-center gap-4 p-8 text-center">
                      <div className="w-20 h-20 bg-[#2c2c2e] rounded-full flex items-center justify-center text-slate-500 mb-2 group-hover:bg-lime-400 group-hover:text-black transition-all duration-500">
                        <ImageIcon className="w-8 h-8" />
                      </div>
                      <p className="text-xl text-slate-500 font-extralight px-4 font-sans">Toque abaixo para gerar a simulação no seu rosto</p>
                    </div>
                  )}

                  {/* Action Buttons Overlay */}
                  {!isLoadingThis && (
                    <div className={`absolute bottom-0 w-full p-6 flex justify-center z-20 ${hasGenerated ? 'bg-gradient-to-t from-black/90 via-black/40 to-transparent pt-20' : ''}`}>

                      {!hasGenerated ? (
                        <button 
                          onClick={() => handleGeneratePreview(index, cut.name)}
                          className="bg-white hover:bg-lime-400 text-black px-6 py-3 rounded-full font-normal text-xl flex items-center gap-2 transition-all shadow-xl hover:scale-105 font-economica uppercase tracking-wide"
                        >
                          <ScanFace className="w-4 h-4" />
                          Simular no meu Rosto
                        </button>
                      ) : (
                        <button 
                          onClick={() => toggleBeforeAfter(index)}
                          className="bg-black/70 hover:bg-black text-white border border-white/20 px-6 py-2.5 rounded-full font-normal text-xl flex items-center gap-2 transition-all backdrop-blur-md font-economica uppercase"
                        >
                          <Layers className="w-3 h-3" />
                          {isShowOriginal ? 'Ver Resultado' : 'Ver Original'}
                        </button>
                      )}
                    </div>
                  )}
                </div>

                {/* Text Content */}
                <div className="p-8 flex flex-col flex-grow">
                  <div className="flex items-center justify-between mb-3">
                     <span className="text-sm font-mono font-medium text-slate-500">#{String(index + 1).padStart(2, '0')}</span>
                     <div className="h-1 w-1 rounded-full bg-lime-400"></div>
                  </div>
                  <h4 className="text-5xl font-display font-medium uppercase text-white mb-4 leading-none tracking-tight">{cut.name}</h4>
                  <p className="text-slate-400 text-2xl leading-relaxed mb-6 flex-grow font-sans font-extralight">
                    {cut.reason}
                  </p>

                  <div className="mt-auto">
                    <a href="#agendamento" className="block w-full text-center py-4 rounded-2xl bg-[#2c2c2e] hover:bg-lime-400 hover:text-black text-white font-normal text-2xl transition-all duration-300 font-economica uppercase tracking-wide">
                      Agendar este Corte
                    </a>
                  </div>
                </div>
              </div>
            );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

