        </p>

        <div className="flex flex-col sm:flex-row gap-5 w-full justify-center">
          <button 
            onClick={onStartVisagism}
            className="group relative flex items-center justify-center gap-3 bg-lime-400 hover:bg-lime-300 text-slate-900 font-normal font-economica text-3xl py-5 px-12 rounded-full transition-all transform hover:scale-105 shadow-[0_0_40px_rgba(163,230,53,0.3)] tracking-wide uppercase"
          >
            <Sparkles className="w-6 h-6 fill-slate-900 group-hover:rotate-12 transition-transform" />
            Análise de Visagismo
          </button>

          <button 
            onClick={onStartScheduling}
