import { Barber, Appointment, TimeSlot, Review } from "../types";

const STORAGE_KEYS = {
  BARBERS: "barberflow_barbers",
  APPOINTMENTS: "barberflow_appointments",
  BLOCKED_SLOTS: "barberflow_blocked_slots",
  REVIEWS: "barberflow_reviews",
};

