                            className="flex-1 py-4 text-slate-500 font-economica text-2xl uppercase hover:text-white transition-colors"
                           >
                            Agora Não
                           </button>
                           <button 
                            type="submit"
                            className="flex-[2] bg-lime-400 text-black py-4 rounded-full font-economica text-2xl uppercase font-bold flex items-center justify-center gap-2 hover:bg-lime-300 transition-all"
                           >
                            Enviar <Send className="w-5 h-5" />
                           </button>
                        </div>
                      </form>
                    </>
                  ) : (
                    <div className="py-12 animate-fade-in">
                       <div className="w-20 h-20 bg-lime-400 rounded-full flex items-center justify-center mx-auto mb-6 shadow-[0_0_30px_rgba(163,230,53,0.4)]">
                        <Check className="w-10 h-10 text-black" />
                      </div>
                      <h3 className="text-6xl font-display font-normal text-white mb-2">Obrigado!</h3>
                      <p className="text-lime-400 text-2xl font-economica uppercase tracking-widest">Sua avaliação foi publicada.</p>
                    </div>
                  )}
               </div>
             )}

          </div>
        </div>
      )}
    </div>
  );
};
